import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { useState, useEffect } from 'react';
import Sidebar from './components/Layout/Sidebar';
import HomePage from './pages/HomePage';
import ListeningPage from './pages/ListeningPage';
import ScenePage from './pages/ScenePage';
import PracticePage from './pages/PracticePage';
import SearchPage from './pages/SearchPage';
import ReviewPage from './pages/ReviewPage';
import SplashScreen from './components/Common/SplashScreen';
import SplashScreenV2 from './components/Common/SplashScreenV2';
import { useSidebarStore } from './store/sidebarStore';
import { useLearningStore } from './store/learningStore';

export default function App() {
  const { collapsed } = useSidebarStore();
  const { darkMode } = useLearningStore();
  const [showSplash, setShowSplash] = useState(true);

  const handleSplashComplete = () => {
    setShowSplash(false);
  };

  if (showSplash) {
    return <SplashScreen onComplete={handleSplashComplete} />;
  }
  
  return (
    <Router>
      <div className={`flex min-h-screen transition-colors duration-300 ${darkMode ? 'bg-slate-900' : 'bg-gray-50'}`}>
        <Sidebar />
        <main 
          className={`flex-1 transition-all duration-300 ${collapsed ? 'lg:ml-20' : 'lg:ml-64'}`}
        >
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/listening" element={<ListeningPage />} />
            <Route path="/scene/:sceneId" element={<ScenePage />} />
            <Route path="/practice/:sceneId" element={<PracticePage />} />
            <Route path="/search" element={<SearchPage />} />
            <Route path="/review" element={<ReviewPage />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
}
