import { useState } from 'react';
import { X, Save } from 'lucide-react';
import { Vocabulary } from '../../store/learningStore';
import { useLearningStore } from '../../store/learningStore';
import { scenes } from '../../data/vocabulary';

interface EditVocabularyModalProps {
  vocabulary: Vocabulary;
  onClose: () => void;
  onUpdate: (updatedVocab: Partial<Omit<Vocabulary, 'id'>>) => void;
}

export default function EditVocabularyModal({ vocabulary, onClose, onUpdate }: EditVocabularyModalProps) {
  const { darkMode, getSceneCategories } = useLearningStore();

  const [formData, setFormData] = useState({
    english: vocabulary.english,
    chinese: vocabulary.chinese,
    phonetic: vocabulary.phonetic,
    scene: vocabulary.scene,
    category: vocabulary.category,
  });

  const [error, setError] = useState('');

  const currentCategories = getSceneCategories(formData.scene);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.english.trim() || !formData.chinese.trim()) {
      setError('请填写英文和中文释义');
      return;
    }
    if (!formData.category.trim()) {
      setError('请选择分类');
      return;
    }

    onUpdate({
      english: formData.english.trim(),
      chinese: formData.chinese.trim(),
      phonetic: formData.phonetic.trim(),
      scene: formData.scene,
      category: formData.category,
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden`}>
        <div className={`bg-gradient-to-r from-blue-600 to-indigo-600 text-white p-6`}>
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold">修改单词</h2>
              <p className="text-blue-100 mt-1 text-sm">
                修改已添加的自定义单词
              </p>
            </div>
            <button
              onClick={onClose}
              className="p-2 hover:bg-white/20 rounded-full transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          {error && (
            <div className={`${darkMode ? 'bg-red-900/30 border-red-700 text-red-400' : 'bg-red-50 border-red-200 text-red-700'} border px-4 py-3 rounded-xl text-sm`}>
              {error}
            </div>
          )}

          <div className="space-y-4">
            <div>
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                英文单词/短语 <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={formData.english}
                onChange={(e) => setFormData({ ...formData, english: e.target.value })}
                placeholder="例如: accommodation"
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 placeholder-slate-400' : 'border-gray-200 bg-gray-50'
                }`}
              />
            </div>

            <div>
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                中文释义 <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={formData.chinese}
                onChange={(e) => setFormData({ ...formData, chinese: e.target.value })}
                placeholder="例如: 住宿"
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 placeholder-slate-400' : 'border-gray-200 bg-gray-50'
                }`}
              />
            </div>

            <div>
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                音标
              </label>
              <input
                type="text"
                value={formData.phonetic}
                onChange={(e) => setFormData({ ...formData, phonetic: e.target.value })}
                placeholder="例如: /əˌkɒməˈdeɪʃn/"
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 placeholder-slate-400' : 'border-gray-200 bg-gray-50'
                }`}
              />
            </div>

            <div>
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                场景分类
              </label>
              <select
                value={formData.scene}
                onChange={(e) => setFormData(prev => ({ ...prev, scene: e.target.value }))}
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100' : 'border-gray-200 bg-gray-50'
                }`}
              >
                {scenes.map((s) => (
                  <option key={s.id} value={s.id}>
                    {s.nameCn} ({s.name})
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                词汇分类 <span className="text-red-500">*</span>
              </label>
              <select
                value={formData.category}
                onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100' : 'border-gray-200 bg-gray-50'
                }`}
              >
                <option value="">选择分类...</option>
                {currentCategories.map((cat) => (
                  <option key={cat} value={cat}>
                    {cat}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="pt-4 flex gap-3">
            <button
              type="button"
              onClick={onClose}
              className={`flex-1 py-4 px-6 rounded-xl font-semibold transition-all ${
                darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              取消
            </button>
            <button
              type="submit"
              className="flex-1 bg-gradient-to-r from-blue-600 to-indigo-600 text-white py-4 px-6 rounded-xl font-semibold hover:from-blue-700 hover:to-indigo-700 transition-all transform hover:scale-[1.01] active:scale-[0.99] shadow-lg shadow-blue-500/30 flex items-center justify-center gap-2"
            >
              <Save className="w-5 h-5" />
              保存修改
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}