function calculateStreak(records: any): number {
  if (!records || typeof records !== 'object' || Object.keys(records).length === 0) return 0;
  
  const dates = Object.values(records)
    .map((r: any) => r.lastStudyTime)
    .filter((time: any) => time > 0)
    .map((time: any) => new Date(time).toDateString());
  
  const uniqueDates = [...new Set(dates)].sort().reverse();
  const today = new Date();
  let streak = 0;
  
  for (let i = 0; i < uniqueDates.length; i++) {
    const checkDate = new Date(today);
    checkDate.setDate(checkDate.getDate() - i);
    if (uniqueDates.includes(checkDate.toDateString())) {
      streak++;
    } else {
      break;
    }
  }
  
  return streak;
}

function generateWeeklyTrendData(records: any, offset: number = 0) {
  const trendData = [];
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  
  const todayDayOfWeek = today.getDay();
  const daysUntilSunday = todayDayOfWeek;
  
  for (let i = 0; i < 7; i++) {
    const date = new Date(today);
    date.setDate(date.getDate() - daysUntilSunday - (offset * 7) + i);
    
    const dateStr = `${date.getFullYear()}/${date.getMonth() + 1}/${date.getDate()}`;
    
    trendData.push({
      dateStr: dateStr,
      dayName: ['日', '一', '二', '三', '四', '五', '六'][date.getDay()],
      learned: 0
    });
  }

  if (records && typeof records === 'object') {
    Object.values(records).forEach((record: any) => {
      if (record.lastStudyTime) {
        try {
          const studyDate = new Date(record.lastStudyTime);
          const studyDateStr = `${studyDate.getFullYear()}/${studyDate.getMonth() + 1}/${studyDate.getDate()}`;
          
          const dayData = trendData.find(d => d.dateStr === studyDateStr);
          if (dayData && record.learned && Array.isArray(record.learned)) {
            dayData.learned += record.learned.length;
          }
        } catch (e) {
          console.error('Error parsing record:', record);
        }
      }
    });
  }

  return trendData;
}

function getRecentActivities() {
  const activities: Array<{text: string; time: string; timestamp: number; color: string}> = [];
  
  const records = useLearningStore.getState().records;
  const reviewRecords = useLearningStore.getState().reviewRecords;
  const customVocabulary = useLearningStore.getState().customVocabulary;
  
  Object.entries(records).forEach(([sceneId, record]: [string, any]) => {
    if (record.lastStudyTime) {
      const scene = scenes.find(s => s.id === sceneId);
      const date = new Date(record.lastStudyTime);
      const timeStr = date.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
      const dateStr = date.toLocaleDateString('zh-CN', { month: 'short', day: 'numeric' });
      
      activities.push({
        text: `学习了 ${scene?.name || sceneId}，已学 ${record.learned?.length || 0} 个词汇`,
        time: `${dateStr} ${timeStr}`,
        timestamp: date.getTime(),
        color: 'bg-emerald-500'
      });
    }
  });
  
  reviewRecords.slice(-5).forEach((record: any) => {
    const vocab = [...vocabularyData, ...customVocabulary].find(v => v.id === record.vocabularyId);
    const date = new Date(record.lastReviewTime || Date.now());
    const timeStr = date.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
    const dateStr = date.toLocaleDateString('zh-CN', { month: 'short', day: 'numeric' });
    
    if (vocab) {
      activities.push({
        text: `复习了 "${vocab.english}" 词汇`,
        time: `${dateStr} ${timeStr}`,
        timestamp: date.getTime(),
        color: 'bg-blue-500'
      });
    }
  });
  
  return activities
    .sort((a, b) => b.timestamp - a.timestamp)
    .slice(0, 10);
}