export interface ReviewRecord {
  vocabularyId: string;
  sceneId: string;
  lastReviewTime: number;
  reviewCount: number;
  nextReviewTime: number;
  interval: number;
}

const REVIEW_INTERVALS = [1, 2, 4, 7, 15, 30, 60];

export function calculateNextReview(reviewCount: number, lastReviewTime: number): { nextTime: number; interval: number } {
  const index = Math.min(reviewCount, REVIEW_INTERVALS.length - 1);
  const intervalDays = REVIEW_INTERVALS[index];
  const nextTime = lastReviewTime + intervalDays * 24 * 60 * 60 * 1000;
  return { nextTime, interval: intervalDays };
}

export function isDueForReview(record: ReviewRecord): boolean {
  return Date.now() >= record.nextReviewTime;
}

export function getDueVocabulary(reviewRecords: ReviewRecord[]): ReviewRecord[] {
  return reviewRecords.filter(isDueForReview);
}

export function getTodayReviewCount(reviewRecords: ReviewRecord[]): number {
  return getDueVocabulary(reviewRecords).length;
}

export function updateReviewRecord(record: ReviewRecord, wasCorrect: boolean): ReviewRecord {
  const newCount = wasCorrect ? record.reviewCount + 1 : Math.max(0, record.reviewCount - 1);
  const now = Date.now();
  const { nextTime, interval } = calculateNextReview(newCount, now);
  
  return {
    ...record,
    reviewCount: newCount,
    lastReviewTime: now,
    nextReviewTime: nextTime,
    interval,
  };
}

export function createNewReviewRecord(vocabularyId: string, sceneId: string): ReviewRecord {
  const now = Date.now();
  const { nextTime, interval } = calculateNextReview(0, now);
  
  return {
    vocabularyId,
    sceneId,
    lastReviewTime: now,
    reviewCount: 0,
    nextReviewTime: nextTime,
    interval,
  };
}
