import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { vocabularyData, scenes } from '../data/vocabulary';
import { ReviewRecord, isDueForReview, updateReviewRecord, createNewReviewRecord, getTodayReviewCount } from '../utils/spacedRepetition';

export interface Vocabulary {
  id: string;
  scene: string;
  category: string;
  english: string;
  phonetic: string;
  chinese: string;
}

export interface LearningRecord {
  learned: string[];
  mastered: string[];
  lastStudyTime: number;
}

interface CustomCategory {
  sceneId: string;
  name: string;
}

interface LearningState {
  records: Record<string, LearningRecord>;
  customVocabulary: Vocabulary[];
  customCategories: CustomCategory[];
  wrongAnswers: Vocabulary[];
  favorites: Vocabulary[];
  reviewRecords: ReviewRecord[];
  darkMode: boolean;
  lastStudiedScene: string | null;
  toggleDarkMode: () => void;
  addLearned: (sceneId: string, vocabularyId: string) => void;
  addMastered: (sceneId: string, vocabularyId: string) => void;
  removeMastered: (sceneId: string, vocabularyId: string) => void;
  getLearnedCount: (sceneId: string) => number;
  getMasteredCount: (sceneId: string) => number;
  isLearned: (sceneId: string, vocabularyId: string) => boolean;
  isMastered: (sceneId: string, vocabularyId: string) => boolean;
  resetProgress: () => void;
  resetSceneProgress: (sceneId: string) => void;
  resetAllProgress: () => void;
  addCustomVocabulary: (vocab: Omit<Vocabulary, 'id'>) => void;
  deleteCustomVocabulary: (id: string) => void;
  updateCustomVocabulary: (id: string, vocab: Partial<Omit<Vocabulary, 'id'>>) => void;
  updateVocabulary: (id: string, vocab: Partial<Omit<Vocabulary, 'id'>>) => void;
  addCustomCategory: (sceneId: string, name: string) => void;
  deleteCustomCategory: (sceneId: string, name: string) => void;
  getAllVocabulary: () => Vocabulary[];
  getVocabularyByScene: (sceneId: string) => Vocabulary[];
  getSceneCategories: (sceneId: string) => string[];
  addWrongAnswer: (vocab: Vocabulary) => void;
  removeWrongAnswer: (id: string) => void;
  resetWrongAnswers: () => void;
  addFavorite: (vocab: Vocabulary) => void;
  removeFavorite: (id: string) => void;
  getAllFavorites: () => Vocabulary[];
  getAllRecords: () => Record<string, LearningRecord>;
  getSceneLearnedCount: (sceneId: string) => number;
  getSceneMasteredCount: (sceneId: string) => number;
  addReviewRecord: (vocabularyId: string, sceneId: string) => void;
  updateReview: (vocabularyId: string, wasCorrect: boolean) => void;
  getDueReviewVocabulary: () => Vocabulary[];
  getTodayReviewCount: () => number;
  getAllReviewRecords: () => ReviewRecord[];
  setLastStudiedScene: (sceneId: string) => void;
  getLastStudiedScene: () => string | null;
  getRecentLearningScenes: () => { id: string; name: string; lastStudyTime: number }[];
}

export const useLearningStore = create<LearningState>()(
  persist(
    (set, get) => ({
      records: {},
      customVocabulary: [],
      customCategories: [],
      wrongAnswers: [],
      favorites: [],
      reviewRecords: [],
      darkMode: false,
      lastStudiedScene: null,
      
      toggleDarkMode: () => {
        set((state) => ({ darkMode: !state.darkMode }));
      },
      
      addLearned: (sceneId, vocabularyId) => {
        set((state) => {
          const sceneRecord = state.records[sceneId] || { learned: [], mastered: [], lastStudyTime: 0 };
          if (!sceneRecord.learned.includes(vocabularyId)) {
            return {
              records: {
                ...state.records,
                [sceneId]: {
                  ...sceneRecord,
                  learned: [...sceneRecord.learned, vocabularyId],
                  lastStudyTime: Date.now(),
                },
              },
            };
          }
          return state;
        });
      },
      
      addMastered: (sceneId, vocabularyId) => {
        set((state) => {
          const sceneRecord = state.records[sceneId] || { learned: [], mastered: [], lastStudyTime: 0 };
          if (!sceneRecord.mastered.includes(vocabularyId)) {
            return {
              records: {
                ...state.records,
                [sceneId]: {
                  ...sceneRecord,
                  learned: sceneRecord.learned.includes(vocabularyId) 
                    ? sceneRecord.learned 
                    : [...sceneRecord.learned, vocabularyId],
                  mastered: [...sceneRecord.mastered, vocabularyId],
                  lastStudyTime: Date.now(),
                },
              },
            };
          }
          return state;
        });
      },
      
      removeMastered: (sceneId, vocabularyId) => {
        set((state) => {
          const sceneRecord = state.records[sceneId];
          if (!sceneRecord) return state;
          return {
            records: {
              ...state.records,
              [sceneId]: {
                ...sceneRecord,
                mastered: sceneRecord.mastered.filter(id => id !== vocabularyId),
              },
            },
          };
        });
      },
      
      getLearnedCount: (sceneId) => {
        const record = get().records[sceneId];
        return record?.learned.length || 0;
      },
      
      getMasteredCount: (sceneId) => {
        const record = get().records[sceneId];
        return record?.mastered.length || 0;
      },
      
      isLearned: (sceneId, vocabularyId) => {
        const record = get().records[sceneId];
        return record?.learned.includes(vocabularyId) || false;
      },
      
      isMastered: (sceneId, vocabularyId) => {
        const record = get().records[sceneId];
        return record?.mastered.includes(vocabularyId) || false;
      },
      
      resetProgress: () => {
        set({ records: {} });
      },

      resetSceneProgress: (sceneId) => {
        set((state) => {
          const newRecords = { ...state.records };
          delete newRecords[sceneId];
          return { records: newRecords };
        });
      },

      resetAllProgress: () => {
        set({ records: {} });
      },
      
      addCustomVocabulary: (vocab) => {
        const id = `custom-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
        const newVocab = { ...vocab, id };
        set((state) => ({
          customVocabulary: [...state.customVocabulary, newVocab],
          reviewRecords: [...state.reviewRecords, createNewReviewRecord(id, vocab.scene)],
        }));
      },
      
      deleteCustomVocabulary: (id) => {
        set((state) => ({
          customVocabulary: state.customVocabulary.filter(v => v.id !== id),
        }));
      },

      updateCustomVocabulary: (id, vocab) => {
        set((state) => ({
          customVocabulary: state.customVocabulary.map(v => 
            v.id === id ? { ...v, ...vocab } : v
          ),
        }));
      },

      updateVocabulary: (id, vocab) => {
        set((state) => {
          const isCustom = state.customVocabulary.some(v => v.id === id);
          if (isCustom) {
            return {
              customVocabulary: state.customVocabulary.map(v => 
                v.id === id ? { ...v, ...vocab } : v
              ),
            };
          } else {
            const existingOverride = state.customVocabulary.find(v => v.id === `${id}_override`);
            if (existingOverride) {
              return {
                customVocabulary: state.customVocabulary.map(v => 
                  v.id === `${id}_override` ? { ...v, ...vocab } : v
                ),
              };
            } else {
              const originalVocab = vocabularyData.find(v => v.id === id);
              if (originalVocab) {
                return {
                  customVocabulary: [...state.customVocabulary, { ...originalVocab, ...vocab, id: `${id}_override` }],
                };
              }
            }
          }
          return state;
        });
      },

      addCustomCategory: (sceneId, name) => {
        set((state) => {
          const exists = state.customCategories.some(
            c => c.sceneId === sceneId && c.name === name
          );
          if (exists) return state;
          return {
            customCategories: [...state.customCategories, { sceneId, name }],
          };
        });
      },

      deleteCustomCategory: (sceneId, name) => {
        set((state) => ({
          customCategories: state.customCategories.filter(
            c => !(c.sceneId === sceneId && c.name === name)
          ),
        }));
      },
      
      getAllVocabulary: () => {
        const custom = get().customVocabulary;
        const overrideMap = new Map<string, Vocabulary>();
        custom.forEach(v => {
          if (v.id.endsWith('_override')) {
            overrideMap.set(v.id.replace('_override', ''), v);
          }
        });
        return vocabularyData.map(v => overrideMap.has(v.id) ? overrideMap.get(v.id)! : v).concat(
          custom.filter(v => !v.id.endsWith('_override'))
        );
      },

      getVocabularyByScene: (sceneId) => {
        const builtin = vocabularyData.filter(v => v.scene === sceneId);
        const custom = get().customVocabulary.filter(v => v.scene === sceneId);
        const overrideMap = new Map<string, Vocabulary>();
        custom.forEach(v => {
          if (v.id.endsWith('_override')) {
            overrideMap.set(v.id.replace('_override', ''), v);
          }
        });
        return builtin.map(v => overrideMap.has(v.id) ? overrideMap.get(v.id)! : v).concat(
          custom.filter(v => !v.id.endsWith('_override'))
        );
      },

      getSceneCategories: (sceneId) => {
        const builtinCategories = vocabularyData
          .filter(v => v.scene === sceneId)
          .map(v => v.category)
          .filter((cat, index, self) => self.indexOf(cat) === index);
        const customCats = get().customCategories
          .filter(c => c.sceneId === sceneId)
          .map(c => c.name);
        return [...builtinCategories, ...customCats];
      },

      addWrongAnswer: (vocab) => {
        set((state) => {
          const exists = state.wrongAnswers.some(v => v.id === vocab.id);
          if (exists) return state;
          return {
            wrongAnswers: [...state.wrongAnswers, vocab],
          };
        });
      },

      removeWrongAnswer: (id) => {
        set((state) => ({
          wrongAnswers: state.wrongAnswers.filter(v => v.id !== id),
        }));
      },

      resetWrongAnswers: () => {
        set({ wrongAnswers: [] });
      },

      addFavorite: (vocab) => {
        set((state) => {
          const exists = state.favorites.some(v => v.id === vocab.id);
          if (exists) return state;
          return {
            favorites: [...state.favorites, vocab],
          };
        });
      },

      removeFavorite: (id) => {
        set((state) => ({
          favorites: state.favorites.filter(v => v.id !== id),
        }));
      },

      getAllFavorites: () => {
        return get().favorites;
      },

      getAllRecords: () => {
        return get().records;
      },

      getSceneLearnedCount: (sceneId) => {
        const record = get().records[sceneId];
        return record?.learned.length || 0;
      },

      getSceneMasteredCount: (sceneId) => {
        const record = get().records[sceneId];
        return record?.mastered.length || 0;
      },

      addReviewRecord: (vocabularyId, sceneId) => {
        set((state) => {
          const exists = state.reviewRecords.some(
            r => r.vocabularyId === vocabularyId && r.sceneId === sceneId
          );
          if (exists) return state;
          return {
            reviewRecords: [...state.reviewRecords, createNewReviewRecord(vocabularyId, sceneId)],
          };
        });
      },

      updateReview: (vocabularyId, wasCorrect) => {
        set((state) => ({
          reviewRecords: state.reviewRecords.map(r =>
            r.vocabularyId === vocabularyId ? updateReviewRecord(r, wasCorrect) : r
          ),
        }));
      },

      getDueReviewVocabulary: () => {
        const dueRecords = get().reviewRecords.filter(isDueForReview);
        const vocabIds = dueRecords.map(r => r.vocabularyId);
        const allVocab = vocabularyData.concat(get().customVocabulary);
        return allVocab.filter(v => vocabIds.includes(v.id));
      },

      getTodayReviewCount: () => {
        return getTodayReviewCount(get().reviewRecords);
      },

      getAllReviewRecords: () => {
        return get().reviewRecords;
      },

      setLastStudiedScene: (sceneId) => {
        set({ lastStudiedScene: sceneId });
      },

      getLastStudiedScene: () => {
        return get().lastStudiedScene;
      },

      getRecentLearningScenes: () => {
        const records = get().records;
        return Object.entries(records)
          .filter(([, record]) => record.lastStudyTime > 0)
          .map(([sceneId, record]) => {
            const scene = scenes.find(s => s.id === sceneId);
            return {
              id: sceneId,
              name: scene?.name || sceneId,
              lastStudyTime: record.lastStudyTime,
            };
          })
          .sort((a, b) => b.lastStudyTime - a.lastStudyTime);
      },
    }),
    {
      name: 'ielts-learning-storage',
    }
  )
);
