import { useState, useEffect } from 'react';
import { useLearningStore, Vocabulary } from '../store/learningStore';
import { Volume2, Check, X, ArrowRight } from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import { findWordParts } from '../data/wordParts';
import { getExamples } from '../data/examples';

export default function ReviewPage() {
  const { getDueReviewVocabulary, updateReview, addReviewRecord, darkMode } = useLearningStore();
  const { speak } = useSpeech();
  
  const [vocabularyList, setVocabularyList] = useState<Vocabulary[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [showAnswer, setShowAnswer] = useState(false);
  const [lastAnswer, setLastAnswer] = useState<'correct' | 'wrong' | null>(null);
  const [completedCount, setCompletedCount] = useState(0);

  useEffect(() => {
    const dueVocab = getDueReviewVocabulary();
    setVocabularyList(dueVocab);
    setCurrentIndex(0);
    setCompletedCount(0);
  }, [getDueReviewVocabulary]);

  const currentVocab = vocabularyList[currentIndex];
  const wordParts = currentVocab ? findWordParts(currentVocab.english) : null;
  const examples = currentVocab ? getExamples(currentVocab.english) : [];

  const handleSpeak = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (currentVocab) {
      speak(currentVocab.english);
    }
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const handleAnswer = (correct: boolean) => {
    if (currentVocab) {
      updateReview(currentVocab.id, correct);
      setLastAnswer(correct ? 'correct' : 'wrong');
      setCompletedCount(prev => prev + 1);
      
      setTimeout(() => {
        if (currentIndex < vocabularyList.length - 1) {
          setCurrentIndex(prev => prev + 1);
          setIsFlipped(false);
          setShowAnswer(false);
          setLastAnswer(null);
        }
      }, 1000);
    }
  };

  if (vocabularyList.length === 0) {
    return (
      <div className={`min-h-screen ${darkMode ? 'bg-slate-900' : 'bg-gray-50'} p-6`}>
        <div className={`max-w-2xl mx-auto text-center p-12 ${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-2xl shadow-lg`}>
          <div className="text-6xl mb-6">🎉</div>
          <h2 className={`text-2xl font-bold mb-4 ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>太棒了！</h2>
          <p className={`${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>
            当前没有需要复习的单词，继续保持！
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen ${darkMode ? 'bg-slate-900' : 'bg-gray-50'} p-6`}>
      <div className="max-w-2xl mx-auto">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className={`text-xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>智能复习</h1>
            <p className={`text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>
              基于艾宾浩斯遗忘曲线
            </p>
          </div>
          <div className={`px-4 py-2 rounded-full ${darkMode ? 'bg-slate-700' : 'bg-gray-100'}`}>
            <span className={`text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-600'}`}>
              {completedCount} / {vocabularyList.length}
            </span>
          </div>
        </div>

        <div className="relative mb-6">
          <div className={`h-2 rounded-full overflow-hidden ${darkMode ? 'bg-slate-700' : 'bg-gray-200'}`}>
            <div 
              className="h-full bg-gradient-to-r from-emerald-500 to-teal-500 transition-all duration-300"
              style={{ width: `${(completedCount / vocabularyList.length) * 100}%` }}
            />
          </div>
        </div>

        <div className="perspective-1000 cursor-pointer" onClick={handleFlip}>
          <div 
            className={`relative w-full h-64 transition-transform duration-500 ${
              isFlipped ? 'rotate-y-180' : ''
            } ${lastAnswer === 'correct' ? 'ring-4 ring-emerald-500' : lastAnswer === 'wrong' ? 'ring-4 ring-red-500' : ''}`}
            style={{
              transformStyle: 'preserve-3d',
              transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)',
            }}
          >
            <div 
              className={`absolute inset-0 ${darkMode ? 'bg-slate-800 border border-slate-700' : 'bg-white'} rounded-2xl shadow-lg p-8 flex flex-col backface-hidden`}
              style={{ backfaceVisibility: 'hidden' }}
            >
              <div className="flex items-center justify-between mb-4">
                <span className={`px-3 py-1 ${darkMode ? 'bg-emerald-900/30 text-emerald-400' : 'bg-primary-50 text-primary-500'} text-xs font-medium rounded-full`}>
                  第 {currentIndex + 1} 个
                </span>
                <button
                  onClick={handleSpeak}
                  className={`p-2 ${darkMode ? 'bg-emerald-900/30 hover:bg-emerald-900/50 text-emerald-400' : 'bg-primary-50 hover:bg-primary-100 text-primary-500'} rounded-xl transition-colors`}
                >
                  <Volume2 className="w-5 h-5" />
                </button>
              </div>
              
              <div className="flex-1 flex flex-col items-center justify-center">
                <h3 className={`font-display text-3xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} mb-2 text-center`}>
                  {currentVocab?.english}
                </h3>
                <p className={`${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>{currentVocab?.phonetic}</p>
              </div>
              
              <p className={`text-center text-sm ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>
                点击卡片查看答案
              </p>
            </div>

            <div 
              className={`absolute inset-0 ${darkMode ? 'bg-slate-700 border border-slate-600' : 'bg-gradient-to-br from-primary-500 to-primary-600'} rounded-2xl shadow-lg p-8 flex flex-col backface-hidden`}
              style={{ 
                backfaceVisibility: 'hidden',
                transform: 'rotateY(180deg)'
              }}
            >
              <h3 className={`font-serif text-3xl font-bold ${darkMode ? 'text-slate-100' : 'text-white'} mb-4 text-center`}>
                {currentVocab?.chinese}
              </h3>
              
              {(wordParts?.prefixes.length || wordParts?.roots.length || wordParts?.suffixes.length) > 0 && (
                <div className="flex flex-wrap justify-center gap-2 mb-4">
                  {wordParts?.prefixes.map((p, i) => (
                    <span key={`p-${i}`} className={`px-2 py-1 rounded text-xs ${darkMode ? 'bg-blue-900/30 text-blue-400' : 'bg-white/20 text-white'}`}>
                      {p.part} {p.meaning}
                    </span>
                  ))}
                  {wordParts?.roots.map((r, i) => (
                    <span key={`r-${i}`} className={`px-2 py-1 rounded text-xs ${darkMode ? 'bg-purple-900/30 text-purple-400' : 'bg-white/20 text-white'}`}>
                      {r.part} {r.meaning}
                    </span>
                  ))}
                  {wordParts?.suffixes.map((s, i) => (
                    <span key={`s-${i}`} className={`px-2 py-1 rounded text-xs ${darkMode ? 'bg-green-900/30 text-green-400' : 'bg-white/20 text-white'}`}>
                      {s.part} {s.meaning}
                    </span>
                  ))}
                </div>
              )}

              {examples.length > 0 && (
                <div className={`mt-4 p-3 rounded-lg ${darkMode ? 'bg-slate-800' : 'bg-white/20'}`}>
                  <p className={`text-sm ${darkMode ? 'text-slate-300' : 'text-white'}`}>{examples[0].sentence}</p>
                  <p className={`text-xs mt-1 ${darkMode ? 'text-slate-400' : 'text-white/70'}`}>{examples[0].translation}</p>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="flex items-center justify-center gap-4 mt-6">
          <button
            onClick={() => handleAnswer(false)}
            className="flex items-center gap-2 px-8 py-4 bg-red-500 hover:bg-red-600 text-white rounded-xl font-medium transition-colors shadow-lg"
          >
            <X className="w-5 h-5" />
            记错了
          </button>
          <button
            onClick={() => handleAnswer(true)}
            className="flex items-center gap-2 px-8 py-4 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-medium transition-colors shadow-lg"
          >
            <Check className="w-5 h-5" />
            记住了
          </button>
        </div>

        <div className={`mt-8 p-6 rounded-xl ${darkMode ? 'bg-slate-800' : 'bg-gray-50'}`}>
          <h3 className={`font-medium mb-3 ${darkMode ? 'text-slate-200' : 'text-gray-700'}`}>复习计划说明</h3>
          <ul className={`space-y-2 text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>
            <li className="flex items-start gap-2">
              <span>📚</span>
              <span>复习间隔：1天 → 2天 → 4天 → 7天 → 15天 → 30天 → 60天</span>
            </li>
            <li className="flex items-start gap-2">
              <span>✅</span>
              <span>答对：进入下一阶段，延长复习间隔</span>
            </li>
            <li className="flex items-start gap-2">
              <span>❌</span>
              <span>答错：退回上一阶段，缩短复习间隔</span>
            </li>
          </ul>
        </div>
      </div>
    </div>
  );
}
