import { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  ArrowLeft, 
  List, 
  Volume2, 
  CheckCircle2, 
  Edit3, 
  Headphones,
  Zap,
  Heart,
  Lightbulb,
  ChevronLeft,
  ChevronRight,
  BookOpen,
  ChevronDown,
  ChevronUp,
  Trash2,
  Plus
} from 'lucide-react';
import { scenes } from '../data/vocabulary';
import { useLearningStore } from '../store/learningStore';
import { useSpeech } from '../hooks/useSpeech';
import { getExamples } from '../data/examples';
import EditVocabularyModal from '../components/Common/EditVocabularyModal';

type ViewMode = 'list' | 'spelling' | 'dictation' | 'flashcard';
type StudyMode = 'sequential' | 'random';

interface VocabState {
  showExamples: boolean;
  showEditModal: boolean;
}

export default function ScenePage() {
  const { sceneId } = useParams<{ sceneId: string }>();
  const navigate = useNavigate();
  const { speak } = useSpeech();
  
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [viewMode, setViewMode] = useState<ViewMode>('list');
  const [studyMode, setStudyMode] = useState<StudyMode>('sequential');
  const [currentWordIndex, setCurrentWordIndex] = useState(0);
  const [userAnswer, setUserAnswer] = useState('');
  const [showResult, setShowResult] = useState(false);
  const [isCorrect, setIsCorrect] = useState(false);
  const [showWord, setShowWord] = useState(false);
  const [showHint, setShowHint] = useState(false);
  const [touchStart, setTouchStart] = useState<number | null>(null);
  const [touchEnd, setTouchEnd] = useState<number | null>(null);
  const [vocabStates, setVocabStates] = useState<Record<string, VocabState>>({});
  const shuffleRef = useRef<number[]>([]);
  
  const { 
    darkMode,
    getSceneCategories, 
    addLearned, 
    getLearnedCount, 
    getMasteredCount, 
    addMastered, 
    removeMastered, 
    isMastered,
    isLearned,
    addWrongAnswer,
    addFavorite,
    removeFavorite,
    getAllFavorites,
    customVocabulary,
    deleteCustomVocabulary,
    updateVocabulary,
    getAllVocabulary,
    getVocabularyByScene
  } = useLearningStore();
  
  const isAllVocab = sceneId === 'all';
  const scene = isAllVocab ? null : scenes.find(s => s.id === sceneId);
  const vocabulary = isAllVocab ? getAllVocabulary() : (sceneId ? getVocabularyByScene(sceneId) : []);
  
  const categories = sceneId ? getSceneCategories(sceneId) : [];
  
  const filteredVocab = vocabulary.filter(v => {
    const categoryMatch = selectedCategory === 'all' || v.category === selectedCategory;
    return categoryMatch;
  });
  
  const getCurrentIndex = () => {
    if (studyMode === 'random' && shuffleRef.current.length > 0) {
      return shuffleRef.current[currentWordIndex];
    }
    return currentWordIndex;
  };
  
  useEffect(() => {
    if (studyMode === 'random' && filteredVocab.length > 0) {
      const indices = filteredVocab.map((_, i) => i);
      for (let i = indices.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [indices[i], indices[j]] = [indices[j], indices[i]];
      }
      shuffleRef.current = indices;
      setCurrentWordIndex(0);
    } else {
      shuffleRef.current = [];
      setCurrentWordIndex(0);
    }
  }, [studyMode]);
  
  useEffect(() => {
    setCurrentWordIndex(0);
  }, [vocabulary.length, selectedCategory]);
  
  const getTotalLearnedCount = () => {
    if (!isAllVocab && sceneId) {
      return getLearnedCount(sceneId);
    }
    return vocabulary.reduce((sum, word) => {
      return sum + (isLearned(word.scene, word.id) ? 1 : 0);
    }, 0);
  };
  
  const getTotalMasteredCount = () => {
    if (!isAllVocab && sceneId) {
      return getMasteredCount(sceneId);
    }
    return vocabulary.reduce((sum, word) => {
      return sum + (isMastered(word.scene, word.id) ? 1 : 0);
    }, 0);
  };
  
  const learnedCount = getTotalLearnedCount();
  const masteredCount = getTotalMasteredCount();

  const currentWord = filteredVocab[getCurrentIndex()];

  useEffect(() => {
    if (viewMode === 'flashcard' && currentWord) {
      const timer = setTimeout(() => {
        speak(currentWord.english);
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [currentWordIndex, viewMode, currentWord, speak]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (viewMode === 'list') return;
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      
      if (viewMode === 'flashcard') {
        if (e.key === ' ' || e.key === 'Space') {
          e.preventDefault();
          setShowWord(!showWord);
        } else if (e.key === 'ArrowLeft') {
          handlePrev();
        } else if (e.key === 'ArrowRight') {
          handleNext();
        }
      } else if (viewMode === 'spelling' || viewMode === 'dictation') {
        if (e.key === 'Enter' && !showResult) {
          handleCheck();
        } else if (e.key === 'Enter' && showResult) {
          handleNext();
        } else if (e.key === 'ArrowLeft') {
          handlePrev();
        } else if (e.key === 'ArrowRight') {
          handleNext();
        }
      }
    };
    
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [viewMode, showWord, showResult]);

  const getProgressPercent = () => {
    if (filteredVocab.length === 0) return 0;
    return ((currentWordIndex + 1) / filteredVocab.length) * 100;
  };

  if (!scene && !isAllVocab) {
    return (
      <div className={`flex items-center justify-center h-screen ${darkMode ? 'bg-slate-900' : 'bg-gray-50'}`}>
        <div className="text-center">
          <h2 className={`text-2xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>场景不存在</h2>
          <button onClick={() => navigate('/listening')} className="btn-primary mt-4">
            返回
          </button>
        </div>
      </div>
    );
  }

  const handleToggleMaster = (vocabId: string, targetSceneId?: string) => {
    const effectiveSceneId = targetSceneId || (isAllVocab ? undefined : sceneId);
    if (!effectiveSceneId) return;
    
    if (isMastered(effectiveSceneId, vocabId)) {
      removeMastered(effectiveSceneId, vocabId);
    } else {
      addMastered(effectiveSceneId, vocabId);
    }
  };

  const handleToggleFavorite = (vocabId: string) => {
    const vocab = filteredVocab.find(v => v.id === vocabId);
    if (!vocab) return;
    
    const currentFavorites = getAllFavorites();
    const isFavorited = currentFavorites.some(v => v.id === vocabId);
    
    if (isFavorited) {
      removeFavorite(vocabId);
    } else {
      addFavorite(vocab);
    }
  };

  const handleCheck = () => {
    if (!currentWord) return;
    
    let correct = false;
    if (viewMode === 'spelling') {
      correct = userAnswer.trim().toLowerCase() === currentWord.english.toLowerCase();
    } else {
      correct = userAnswer.trim().toLowerCase() === currentWord.chinese.toLowerCase();
    }
    
    setIsCorrect(correct);
    setShowResult(true);
    
    const targetSceneId = isAllVocab ? currentWord.scene : sceneId;
    if (targetSceneId && currentWord) {
      if (correct) {
        addMastered(targetSceneId, currentWord.id);
      } else {
        addLearned(targetSceneId, currentWord.id);
        addWrongAnswer(currentWord);
      }
    }
  };

  const handleNext = () => {
    setCurrentWordIndex(prev => (prev + 1) % filteredVocab.length);
    setUserAnswer('');
    setShowResult(false);
    setIsCorrect(false);
    setShowHint(false);
  };

  const handlePrev = () => {
    setCurrentWordIndex(prev => (prev - 1 + filteredVocab.length) % filteredVocab.length);
    setUserAnswer('');
    setShowResult(false);
    setIsCorrect(false);
    setShowHint(false);
  };

  const minSwipeDistance = 50;

  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(null);
    setTouchStart(e.targetTouches[0].clientX);
  };

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd(e.targetTouches[0].clientX);
  };

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return;
    
    const distance = touchStart - touchEnd;
    const isLeftSwipe = distance > minSwipeDistance;
    const isRightSwipe = distance < -minSwipeDistance;
    
    if (isLeftSwipe) {
      handleNext();
    }
    if (isRightSwipe) {
      handlePrev();
    }
  };

  const toggleExamples = (vocabId: string) => {
    setVocabStates(prev => ({
      ...prev,
      [vocabId]: {
        ...prev[vocabId],
        showExamples: !prev[vocabId]?.showExamples
      }
    }));
  };

  const openEditModal = (vocabId: string) => {
    setVocabStates(prev => ({
      ...prev,
      [vocabId]: {
        ...prev[vocabId],
        showEditModal: true
      }
    }));
  };

  const closeEditModal = (vocabId: string) => {
    setVocabStates(prev => ({
      ...prev,
      [vocabId]: {
        ...prev[vocabId],
        showEditModal: false
      }
    }));
  };

  const handleUpdateVocabulary = (vocabId: string, updatedVocab: Partial<{ english: string; chinese: string; phonetic: string; scene: string; category: string }>) => {
    updateVocabulary(vocabId, updatedVocab);
    closeEditModal(vocabId);
  };

  const handleDeleteCustomVocab = (vocabId: string) => {
    if (vocabId.startsWith('custom-')) {
      deleteCustomVocabulary(vocabId);
    }
  };

  const isCustomWord = (vocabId: string) => {
    return vocabId.startsWith('custom-');
  };

  const canEditWord = (word: { id: string }) => {
    return true;
  };

  const canDeleteWord = (word: { id: string }) => {
    return word.id.startsWith('custom-');
  };

  return (
    <div className={`min-h-screen ${darkMode ? 'bg-slate-900' : 'bg-gray-50'}`}>
      <div className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-200'} border-b sticky top-0 z-40`}>
        <div className="px-6 py-4 max-w-6xl mx-auto">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button
                onClick={() => navigate('/listening')}
                className={`p-2 ${darkMode ? 'hover:bg-slate-700' : 'hover:bg-gray-100'} rounded-xl transition-colors`}
              >
                <ArrowLeft className={`w-5 h-5 ${darkMode ? 'text-slate-400' : 'text-gray-600'}`} />
              </button>
              <div>
              <h1 className={`font-serif text-xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>
                {isAllVocab ? '全部词汇' : scene?.nameCn}
              </h1>
              <p className={`text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>{isAllVocab ? '所有场景词汇汇总' : scene?.name}</p>
            </div>
          </div>
          
          <div className="flex items-center gap-3 mt-3">
            <div className={`${darkMode ? 'bg-slate-700' : 'bg-gray-100'} rounded-xl p-1`}>
              <button
                onClick={() => setStudyMode('sequential')}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                  studyMode === 'sequential' 
                    ? `${darkMode ? 'bg-slate-600 text-emerald-400' : 'bg-white shadow text-emerald-600'}` 
                    : `${darkMode ? 'text-slate-300' : 'text-gray-600'}`
                }`}
              >
                顺序
              </button>
              <button
                onClick={() => setStudyMode('random')}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                  studyMode === 'random' 
                    ? `${darkMode ? 'bg-slate-600 text-emerald-400' : 'bg-white shadow text-emerald-600'}` 
                    : `${darkMode ? 'text-slate-300' : 'text-gray-600'}`
                }`}
              >
                随机
              </button>
            </div>
            
            <div className={`${darkMode ? 'bg-slate-700' : 'bg-gray-100'} rounded-xl p-1`}>
              <button
                onClick={() => setViewMode('list')}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'list' 
                    ? `${darkMode ? 'bg-slate-600 text-emerald-400' : 'bg-white shadow text-emerald-600'}` 
                    : `${darkMode ? 'text-slate-300' : 'text-gray-600'}`
                }`}
              >
                <List className="w-4 h-4 inline mr-2" />
                单词
              </button>
              <button
                onClick={() => setViewMode('flashcard')}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'flashcard' 
                    ? `${darkMode ? 'bg-slate-600 text-emerald-400' : 'bg-white shadow text-emerald-600'}` 
                    : `${darkMode ? 'text-slate-300' : 'text-gray-600'}`
                }`}
              >
                <Zap className="w-4 h-4 inline mr-2" />
                速刷
              </button>
              <button
                onClick={() => setViewMode('spelling')}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  viewMode === 'spelling' 
                    ? `${darkMode ? 'bg-slate-600 text-emerald-400' : 'bg-white shadow text-emerald-600'}` 
                    : `${darkMode ? 'text-slate-300' : 'text-gray-600'}`
                }`}
              >
                <Edit3 className="w-4 h-4 inline mr-2" />
                拼写
              </button>
                <button
                  onClick={() => setViewMode('dictation')}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                    viewMode === 'dictation' 
                      ? `${darkMode ? 'bg-slate-600 text-emerald-400' : 'bg-white shadow text-emerald-600'}` 
                      : `${darkMode ? 'text-slate-300' : 'text-gray-600'}`
                  }`}
                >
                  <Headphones className="w-4 h-4 inline mr-2" />
                  听写
                </button>
              </div>
            </div>
          </div>
          
          <div className={`flex items-center gap-4 mt-4 text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>
            <span>
              已学习 <span className={`font-medium ${darkMode ? 'text-emerald-400' : 'text-emerald-600'}`}>{learnedCount}</span> / {vocabulary.length}
            </span>
            <span>
              已掌握 <span className={`font-medium ${darkMode ? 'text-amber-400' : 'text-amber-600'}`}>{masteredCount}</span>
            </span>
          </div>
        </div>
        
        <div className="px-6 pb-4 max-w-6xl mx-auto">
          <div className="flex gap-2 overflow-x-auto pb-2">
            <button
              onClick={() => setSelectedCategory('all')}
              className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                selectedCategory === 'all'
                  ? `${darkMode ? 'bg-emerald-600 text-white' : 'bg-emerald-500 text-white'}`
                  : `${darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`
              }`}
            >
              全部
            </button>
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                  selectedCategory === cat
                    ? `${darkMode ? 'bg-emerald-600 text-white' : 'bg-emerald-500 text-white'}`
                    : `${darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="px-6 py-8 max-w-6xl mx-auto">
        {viewMode === 'list' ? (
          <div className="grid gap-4">
            {filteredVocab.map((word) => {
              const examples = getExamples(word.english);
              const hasExamples = examples.length > 0;
              const showExamples = vocabStates[word.id]?.showExamples || false;
              const isCustom = isCustomWord(word.id);
              
              return (
                <div key={word.id} className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-100'} rounded-2xl p-4 shadow-sm border animate-slide-up`}>
                  <div className="flex items-center gap-4">
                    <button
                      onClick={() => handleToggleMaster(word.id, word.scene)}
                      className={`p-2 rounded-xl ${darkMode ? 'hover:bg-slate-700' : 'hover:bg-gray-100'} transition-colors`}
                    >
                      {isMastered(word.scene, word.id) ? (
                        <CheckCircle2 className="w-6 h-6 text-amber-500" />
                      ) : (
                        <div className={`w-6 h-6 rounded-full border-2 ${darkMode ? 'border-slate-600' : 'border-gray-300'} flex items-center justify-center`} />
                      )}
                    </button>
                    <div className="flex-1">
                      <h3 className={`text-lg font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>{word.english}</h3>
                      <p className={`text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>{word.chinese}</p>
                      {word.phonetic && <p className={`text-xs ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>{word.phonetic}</p>}
                    </div>
                    <div className="flex items-center gap-2">
                      {hasExamples && (
                        <button
                          onClick={() => toggleExamples(word.id)}
                          className={`p-2 rounded-xl ${darkMode ? 'bg-orange-900/30 text-orange-400 hover:bg-orange-900/50' : 'bg-orange-100 text-orange-600 hover:bg-orange-200'} transition-colors`}
                          title="查看例句"
                        >
                          {showExamples ? <ChevronUp className="w-5 h-5" /> : <BookOpen className="w-5 h-5" />}
                        </button>
                      )}
                      <button
                        onClick={() => speak(word.english)}
                        className={`p-2 ${darkMode ? 'bg-emerald-900 text-emerald-400 hover:bg-emerald-800' : 'bg-emerald-100 text-emerald-600 hover:bg-emerald-200'} rounded-xl transition-colors`}
                      >
                        <Volume2 className="w-5 h-5" />
                      </button>
                      <button
                        onClick={() => openEditModal(word.id)}
                        className={`p-2 rounded-xl ${darkMode ? 'bg-blue-900/30 text-blue-400 hover:bg-blue-900/50' : 'bg-blue-100 text-blue-600 hover:bg-blue-200'} transition-colors`}
                        title="修改单词"
                      >
                        <Edit3 className="w-5 h-5" />
                      </button>
                      {isCustom && (
                        <button
                          onClick={() => handleDeleteCustomVocab(word.id)}
                          className={`p-2 rounded-xl ${darkMode ? 'bg-red-900/30 text-red-400 hover:bg-red-900/50' : 'bg-red-100 text-red-600 hover:bg-red-200'} transition-colors`}
                          title="删除单词"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      )}
                    </div>
                  </div>
                  {showExamples && hasExamples && (
                    <div className={`mt-3 pt-3 border-t ${darkMode ? 'border-slate-700' : 'border-gray-100'}`}>
                      <p className={`text-xs font-medium mb-2 ${darkMode ? 'text-amber-400' : 'text-amber-600'}`}>例句</p>
                      <div className="space-y-2">
                        {examples.map((example, index) => (
                          <div key={index} className={`p-2 rounded-lg ${darkMode ? 'bg-slate-700/50' : 'bg-gray-50'}`}>
                            <p className={`text-sm ${darkMode ? 'text-slate-200' : 'text-gray-800'}`}>{example.sentence}</p>
                            <p className={`text-xs ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>{example.translation}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ) : viewMode === 'flashcard' ? (
          <div className="max-w-2xl mx-auto">
            <div className="mb-4 sm:mb-6">
              <div className={`flex items-center justify-between text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'} mb-2`}>
                <span>进度 {currentWordIndex + 1} / {filteredVocab.length}</span>
                <span>{Math.round(getProgressPercent())}%</span>
              </div>
              <div className={`h-1.5 sm:h-2 ${darkMode ? 'bg-slate-700' : 'bg-gray-200'} rounded-full overflow-hidden`}>
                <div 
                  className="h-full bg-gradient-to-r from-emerald-500 to-teal-400 rounded-full transition-all duration-500"
                  style={{ width: `${getProgressPercent()}%` }}
                />
              </div>
            </div>

            <div 
              className="relative"
              onTouchStart={onTouchStart}
              onTouchMove={onTouchMove}
              onTouchEnd={onTouchEnd}
            >
              <div 
                className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-100'} rounded-2xl p-5 sm:p-6 lg:p-8 shadow-lg border cursor-pointer hover:shadow-xl transition-all`}
                onClick={() => setShowWord(!showWord)}
              >
                <div className="text-center mb-4">
                  <div className="flex items-center justify-center gap-2 sm:gap-3 mb-3 sm:mb-4">
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleToggleFavorite(currentWord?.id || '');
                      }}
                      className={`p-1.5 sm:p-2 rounded-xl ${darkMode ? 'hover:bg-slate-700' : 'hover:bg-gray-100'} transition-colors`}
                    >
                      <Heart 
                        className={`w-5 h-5 sm:w-6 ${
                        getAllFavorites().some(v => v.id === currentWord?.id) 
                          ? 'fill-red-500 text-red-500' 
                          : `${darkMode ? 'text-slate-500' : 'text-gray-400'}`
                      }`} 
                      />
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        setShowHint(!showHint);
                      }}
                      className={`p-1.5 sm:p-2 ${darkMode ? 'bg-amber-900 text-amber-400 hover:bg-amber-800' : 'bg-amber-100 text-amber-600 hover:bg-amber-200'} rounded-xl transition-colors`}
                    >
                      <Lightbulb className="w-5 h-5 sm:w-6" />
                    </button>
                  </div>
                  
                  {showHint && (
                    <div className={`mb-3 sm:mb-4 p-2 sm:p-3 ${darkMode ? 'bg-slate-700' : 'bg-amber-50'} rounded-xl`}>
                      <p className={`${darkMode ? 'text-amber-300' : 'text-amber-700'} text-base sm:text-lg font-bold`}>{currentWord?.english}</p>
                      {currentWord?.phonetic && (
                        <p className={`${darkMode ? 'text-amber-400' : 'text-amber-600'} text-xs sm:text-sm`}>{currentWord.phonetic}</p>
                      )}
                    </div>
                  )}

                  <div className="mb-3 sm:mb-4">
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        speak(currentWord?.english || '');
                      }}
                      className="w-14 h-14 sm:w-16 sm:h-16 lg:w-20 lg:h-20 mx-auto bg-gradient-to-br from-emerald-500 to-teal-500 rounded-full flex items-center justify-center shadow-lg hover:scale-105 transition-transform"
                    >
                      <Volume2 className="w-7 h-7 sm:w-8 lg:w-10 lg:h-10 text-white" />
                    </button>
                  </div>
                  
                  {showWord ? (
                    <div className="animate-fade-in">
                      <h2 className={`text-2xl sm:text-3xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} mb-1`}>
                        {currentWord?.chinese}
                      </h2>
                      {currentWord?.phonetic && (
                        <p className={`${darkMode ? 'text-slate-500' : 'text-gray-400'} text-sm`}>{currentWord.phonetic}</p>
                      )}
                    </div>
                  ) : (
                    <p className={`text-xs sm:text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>点击卡片查看释义</p>
                  )}
                </div>
              </div>

              <div className="flex items-center justify-center mt-4 sm:mt-6">
                <button
                  onClick={handlePrev}
                  disabled={currentWordIndex === 0}
                  className={`p-2 sm:p-3 ${darkMode ? 'bg-slate-800 text-slate-400 hover:bg-slate-700' : 'bg-white text-gray-600 hover:shadow-md'} rounded-full shadow transition-all disabled:opacity-30 disabled:cursor-not-allowed`}
                >
                  <ChevronLeft className="w-5 h-5 sm:w-6 sm:h-6" />
                </button>
                
                <div className="mx-3 sm:mx-4 flex items-center gap-2 sm:gap-3">
                  <button
                    onClick={() => currentWord && handleToggleMaster(currentWord.id, currentWord.scene)}
                    className={`px-4 sm:px-5 py-2 sm:py-3 rounded-xl font-medium text-sm sm:text-base transition-colors ${
                      currentWord && isMastered(currentWord.scene, currentWord.id)
                        ? `${darkMode ? 'bg-amber-600 text-white' : 'bg-amber-500 text-white'}`
                        : `${darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`
                    }`}
                  >
                    {currentWord && isMastered(currentWord.scene, currentWord.id) ? '已掌握' : '标记掌握'}
                  </button>
                </div>
                
                <button
                  onClick={handleNext}
                  className={`p-2 sm:p-3 ${darkMode ? 'bg-slate-800 text-slate-400 hover:bg-slate-700' : 'bg-white text-gray-600 hover:shadow-md'} rounded-full shadow transition-all`}
                >
                  <ChevronRight className="w-5 h-5 sm:w-6 sm:h-6" />
                </button>
              </div>

              <div className={`mt-4 text-center ${darkMode ? 'text-slate-500' : 'text-gray-400'} text-xs`}>
                <span className="hidden sm:inline">空格键翻转卡片</span>
                <span className="sm:hidden">点击翻转</span>
                <span className="mx-2">·</span>
                <span className="hidden sm:inline">方向键切换单词</span>
                <span className="sm:hidden">滑动切换</span>
              </div>
            </div>
          </div>
        ) : (
          currentWord && (
            <div className="max-w-2xl mx-auto">
              <div className="mb-6">
                <div className={`flex items-center justify-between text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'} mb-2`}>
                  <span>进度 {currentWordIndex + 1} / {filteredVocab.length}</span>
                  <span>{Math.round(getProgressPercent())}%</span>
                </div>
                <div className={`h-2 ${darkMode ? 'bg-slate-700' : 'bg-gray-200'} rounded-full overflow-hidden`}>
                  <div 
                    className="h-full bg-gradient-to-r from-emerald-500 to-teal-400 rounded-full transition-all duration-500"
                    style={{ width: `${getProgressPercent()}%` }}
                  />
                </div>
              </div>

              <div 
                className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-100'} rounded-2xl p-5 sm:p-6 shadow-sm border`}
                onTouchStart={onTouchStart}
                onTouchMove={onTouchMove}
                onTouchEnd={onTouchEnd}
              >
                <div className="text-center mb-4 sm:mb-6">
                  {viewMode === 'spelling' ? (
                    <>
                      <h2 className={`text-xl sm:text-2xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} mb-1`}>{currentWord.chinese}</h2>
                      {currentWord.phonetic && (
                        <p className={`${darkMode ? 'text-slate-500' : 'text-gray-400'} text-sm`}>{currentWord.phonetic}</p>
                      )}
                    </>
                  ) : (
                    <>
                      <button
                        onClick={() => speak(currentWord.english)}
                        className="w-14 h-14 sm:w-16 sm:h-16 mx-auto mb-3 sm:mb-4 bg-gradient-to-br from-emerald-500 to-teal-500 rounded-full flex items-center justify-center shadow-lg hover:scale-105 transition-transform"
                      >
                        <Volume2 className="w-8 h-8" />
                      </button>
                      <button
                        onClick={() => setShowWord(!showWord)}
                        className={`text-xl sm:text-2xl lg:text-3xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} ${darkMode ? 'hover:text-emerald-400' : 'hover:text-emerald-600'} transition-colors`}
                      >
                        {showWord ? currentWord.english : '点击显示单词'}
                      </button>
                      {currentWord.phonetic && (
                        <p className={`${darkMode ? 'text-slate-500' : 'text-gray-400'} text-sm mt-1`}>{currentWord.phonetic}</p>
                      )}
                    </>
                  )}
                </div>

                <div className="mb-4 sm:mb-5">
                  <input
                    type="text"
                    value={userAnswer}
                    onChange={(e) => setUserAnswer(e.target.value)}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' && !showResult) {
                        handleCheck();
                      } else if (e.key === 'Enter' && showResult) {
                        handleNext();
                      }
                    }}
                    placeholder={viewMode === 'spelling' ? "请输入英文单词" : "请输入中文释义..."}
                    disabled={showResult}
                    className={`w-full px-6 py-4 text-center text-xl border-2 rounded-2xl focus:outline-none transition-colors ${
                      showResult
                        ? isCorrect
                          ? `${darkMode ? 'border-emerald-500 bg-emerald-900/30 text-emerald-400' : 'border-emerald-500 bg-emerald-50 text-emerald-700'}`
                          : `${darkMode ? 'border-red-500 bg-red-900/30 text-red-400' : 'border-red-500 bg-red-50 text-red-700'}`
                        : `${darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 focus:border-emerald-500' : 'border-gray-200 focus:border-emerald-500'}`
                    }`}
                  />
                </div>

                {showResult && (
                  <div className={`mb-4 sm:mb-5 p-3 sm:p-4 rounded-xl ${
                    isCorrect ? `${darkMode ? 'bg-emerald-900/30' : 'bg-emerald-50'}` : `${darkMode ? 'bg-red-900/30' : 'bg-red-50'}`
                  }`}>
                    {!isCorrect && (
                      <div className="text-center">
                        <p className={`text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'} mb-1`}>正确答案：</p>
                        <p className={`text-lg sm:text-xl font-bold ${darkMode ? 'text-emerald-400' : 'text-emerald-600'}`}>
                          {viewMode === 'spelling' ? currentWord.english : currentWord.chinese}
                        </p>
                      </div>
                    )}
                  </div>
                )}

                <div className="flex items-center justify-center gap-3 sm:gap-4">
                  <button
                    onClick={handlePrev}
                    disabled={currentWordIndex === 0}
                    className={`p-2 sm:p-3 ${darkMode ? 'bg-slate-800 text-slate-400 hover:bg-slate-700' : 'bg-white text-gray-600 hover:shadow-md'} rounded-full shadow transition-all disabled:opacity-30 disabled:cursor-not-allowed`}
                  >
                    <ChevronLeft className="w-5 h-5 sm:w-6 sm:h-6" />
                  </button>
                  
                  {!showResult ? (
                    <button
                      onClick={handleCheck}
                      className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white px-4 sm:px-6 py-3 sm:py-4 rounded-xl transition-colors text-base sm:text-lg"
                      disabled={!userAnswer.trim()}
                    >
                      提交答案
                    </button>
                  ) : (
                    <button
                      onClick={handleNext}
                      className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white px-4 sm:px-6 py-3 sm:py-4 rounded-xl transition-colors text-base sm:text-lg"
                    >
                      {currentWordIndex < filteredVocab.length - 1 ? '下一个' : '完成'}
                    </button>
                  )}
                  
                  <button
                    onClick={handleNext}
                    className={`p-2 sm:p-3 ${darkMode ? 'bg-slate-800 text-slate-400 hover:bg-slate-700' : 'bg-white text-gray-600 hover:shadow-md'} rounded-full shadow transition-all`}
                  >
                    <ChevronRight className="w-5 h-5 sm:w-6 sm:h-6" />
                  </button>
                </div>
              </div>
            </div>
          )
        )}
      </div>

      {Object.entries(vocabStates).map(([vocabId, state]) => {
        if (state.showEditModal) {
          const vocab = filteredVocab.find(v => v.id === vocabId);
          if (vocab) {
            return (
              <EditVocabularyModal
                key={vocabId}
                vocabulary={vocab}
                onClose={() => closeEditModal(vocabId)}
                onUpdate={(updated) => handleUpdateVocabulary(vocabId, updated)}
              />
            );
          }
        }
        return null;
      })}
    </div>
  );
}
