import { useState, useEffect } from 'react';
import { BookOpen, Brain, Target, ChevronRight, TrendingUp, BookMarked, Search, Plus, Mic, Award, Zap } from 'lucide-react';

interface SplashScreenProps {
  onComplete: () => void;
}

export default function SplashScreen({ onComplete }: SplashScreenProps) {
  const [isReady, setIsReady] = useState(false);
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsReady(true);
    }, 800);
    return () => clearTimeout(timer);
  }, []);

  const handleStart = () => {
    setIsVisible(false);
    setTimeout(onComplete, 500);
  };

  const features = [
    { icon: BookOpen, title: '场景词汇学习', desc: '8大雅思听力场景，分类记忆更高效', available: true },
    { icon: TrendingUp, title: '进度追踪', desc: '数据可视化，学习成果一目了然', available: true },
    { icon: Target, title: '智能练习', desc: '多种练习模式，边学边练', available: true },
    { icon: BookMarked, title: '收藏夹', desc: '收藏生词，方便复习', available: true },
    { icon: Search, title: '智能搜索', desc: '快速查找词汇', available: true },
    { icon: Plus, title: '自定义词汇', desc: '添加个人专属词汇', available: true },
  ];

  const comingSoon = [
    { icon: Mic, title: '跟读练习', desc: '智能语音识别，提升口语' },
    { icon: Award, title: '掌握度分析', desc: 'AI评估，定位薄弱环节' },
    { icon: Zap, title: 'AI助手', desc: '智能问答，个性化辅导' },
  ];

  const floatingWords = [
    'IELTS', 'Vocabulary', 'Learning', 'Progress', 'Success', 'Achievement',
    'Accommodation', 'Education', 'Environment', 'Communication', 'Development'
  ];

  return (
    <div 
      className={`fixed inset-0 z-50 flex flex-col items-center justify-start bg-gradient-to-br from-emerald-600 via-teal-600 to-cyan-700 transition-all duration-500 overflow-y-auto ${
        isVisible ? 'opacity-100' : 'opacity-0'
      }`}
      style={{ paddingTop: '10vh', paddingBottom: '10vh' }}
    >
      <div className="absolute inset-0 overflow-hidden">
        {floatingWords.map((word, index) => (
          <div
            key={word}
            className="absolute text-white/5 font-bold animate-float"
            style={{
              fontSize: `${Math.random() * 40 + 20}px`,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              animationDelay: `${index * 0.5}s`,
              animationDuration: `${Math.random() * 10 + 15}s`,
              transform: `rotate(${Math.random() * 30 - 15}deg)`,
            }}
          >
            {word}
          </div>
        ))}
        
        <div className="absolute top-0 left-0 w-full h-full">
          <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-emerald-400/20 rounded-full blur-3xl animate-pulse-slow" />
          <div className="absolute bottom-1/4 right-1/4 w-80 h-80 bg-cyan-400/20 rounded-full blur-3xl animate-pulse-slow" style={{ animationDelay: '1s' }} />
        </div>
      </div>

      <div className="relative z-10 text-center max-w-5xl mx-auto px-8">
        <div className="relative mb-8">
          <div className="flex items-center justify-center gap-6 mb-6">
            <div className="w-20 h-20 bg-white/10 backdrop-blur-lg rounded-2xl flex items-center justify-center border border-white/20 animate-fade-in-down" style={{ animationDelay: '0.2s' }}>
              <BookOpen className="w-10 h-10 text-white" />
            </div>
            <div className="w-20 h-20 bg-white/10 backdrop-blur-lg rounded-2xl flex items-center justify-center border border-white/20 animate-fade-in-down" style={{ animationDelay: '0.4s' }}>
              <Brain className="w-10 h-10 text-white" />
            </div>
            <div className="w-20 h-20 bg-white/10 backdrop-blur-lg rounded-2xl flex items-center justify-center border border-white/20 animate-fade-in-down" style={{ animationDelay: '0.6s' }}>
              <Target className="w-10 h-10 text-white" />
            </div>
          </div>
          
          <h1 className="text-5xl font-bold text-white mb-3 animate-fade-in-up" style={{ animationDelay: '0.3s', letterSpacing: '-0.02em' }}>
            IELTS Learning Platform
          </h1>
          <p className="text-xl text-emerald-100/80 animate-fade-in-up" style={{ animationDelay: '0.5s' }}>
            Build a solid foundation, achieve your dreams
          </p>
        </div>

        <div className="mt-8 flex items-center justify-center gap-8 animate-fade-in-up" style={{ animationDelay: '0.6s' }}>
          <div className="flex items-center gap-2 text-emerald-100/60">
            <div className="w-2 h-2 bg-emerald-300 rounded-full animate-bounce" style={{ animationDelay: '0s' }} />
            <span className="text-sm">Smart Learning</span>
          </div>
          <div className="flex items-center gap-2 text-emerald-100/60">
            <div className="w-2 h-2 bg-cyan-300 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }} />
            <span className="text-sm">Ebbinghaus Curve</span>
          </div>
          <div className="flex items-center gap-2 text-emerald-100/60">
            <div className="w-2 h-2 bg-teal-300 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }} />
            <span className="text-sm">Progress Tracking</span>
          </div>
        </div>

        <div className="mt-12 animate-fade-in-up" style={{ animationDelay: '0.7s' }}>
          <button
            onClick={handleStart}
            disabled={!isReady}
            className={`group relative px-12 py-4 rounded-full font-semibold text-lg transition-all duration-300 ${
              isReady 
                ? 'bg-white text-emerald-600 hover:bg-emerald-50 hover:scale-105 shadow-2xl shadow-white/30' 
                : 'bg-white/50 text-emerald-600/50 cursor-not-allowed'
            }`}
          >
            <span className="flex items-center gap-3">
              {isReady ? 'Start' : 'Loading...'}
              <ChevronRight className={`w-5 h-5 transition-transform duration-300 ${isReady ? 'group-hover:translate-x-1' : ''}`} />
            </span>
          </button>
        </div>

        {/* 功能介绍区域 */}
        <div className="mt-16 animate-fade-in-up" style={{ animationDelay: '0.9s' }}>
          <p className="text-emerald-100/60 text-sm mb-6">平台核心功能</p>
          <div className="grid grid-cols-3 gap-4">
            {features.map((feature) => (
              <div 
                key={feature.title}
                className="group bg-white/10 backdrop-blur-md rounded-2xl p-5 border border-white/20 hover:bg-white/20 transition-all duration-300 hover:scale-105 cursor-default"
              >
                <div className="w-12 h-12 bg-gradient-to-br from-emerald-400/30 to-teal-400/30 rounded-xl flex items-center justify-center mb-3 mx-auto group-hover:from-emerald-400/50 group-hover:to-teal-400/50 transition-all">
                  <feature.icon className="w-6 h-6 text-white" />
                </div>
                <h3 className="text-white font-semibold text-sm mb-1">{feature.title}</h3>
                <p className="text-emerald-100/60 text-xs">{feature.desc}</p>
              </div>
            ))}
          </div>
          
          <p className="text-emerald-100/40 text-sm mt-10 mb-6">敬请期待</p>
          <div className="grid grid-cols-3 gap-4">
            {comingSoon.map((feature) => (
              <div 
                key={feature.title}
                className="group bg-white/5 backdrop-blur-md rounded-2xl p-5 border border-white/10 opacity-60 hover:opacity-80 transition-all duration-300 cursor-default"
              >
                <div className="w-12 h-12 bg-gradient-to-br from-slate-400/30 to-gray-400/30 rounded-xl flex items-center justify-center mb-3 mx-auto">
                  <feature.icon className="w-6 h-6 text-white/70" />
                </div>
                <h3 className="text-white/70 font-semibold text-sm mb-1">{feature.title}</h3>
                <p className="text-white/40 text-xs">{feature.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0) rotate(var(--rotation, 0deg)); }
          50% { transform: translateY(-20px) rotate(var(--rotation, 0deg)); }
        }
        
        @keyframes fade-in-down {
          from { opacity: 0; transform: translateY(-20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        
        @keyframes fade-in-up {
          from { opacity: 0; transform: translateY(20px); }
          to { opacity: 1; transform: translateY(0); }
        }
        
        @keyframes pulse-slow {
          0%, 100% { opacity: 0.3; transform: scale(1); }
          50% { opacity: 0.5; transform: scale(1.1); }
        }
        
        .animate-float {
          animation: float 15s ease-in-out infinite;
        }
        
        .animate-fade-in-down {
          animation: fade-in-down 0.6s ease-out forwards;
          opacity: 0;
        }
        
        .animate-fade-in-up {
          animation: fade-in-up 0.6s ease-out forwards;
          opacity: 0;
        }
        
        .animate-pulse-slow {
          animation: pulse-slow 4s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
}
