export function findWordParts(word: string): { prefixes: WordPart[]; roots: WordPart[]; suffixes: WordPart[] } {
  const lowerWord = word.toLowerCase();
  
  const foundPrefixes = prefixes.filter(p => lowerWord.startsWith(p.part.toLowerCase()));
  const foundSuffixes = suffixes.filter(s => lowerWord.endsWith(s.part.toLowerCase().replace('-', '')));
  
  const foundRoots: WordPart[] = [];
  for (const root of roots) {
    const rootPart = root.part.toLowerCase().replace('/', '');
    if (lowerWord.includes(rootPart)) {
      foundRoots.push(root);
    }
  }
  
  return { prefixes: foundPrefixes, roots: foundRoots, suffixes: foundSuffixes };
}
