export const getSceneVocabulary = (sceneId: string) => {
  return vocabularyData.filter(v => v.scene === sceneId);
};

export const getAllVocabulary = () => {
  return vocabularyData;
};

export const searchVocabulary = (query: string) => {
  const lowerQuery = query.toLowerCase();
  return vocabularyData.filter(v => 
    v.english.toLowerCase().includes(lowerQuery) || 
    v.chinese.includes(query)
  );
};

