import { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Shuffle, List, Volume2, Check, X, RotateCcw, BookOpen } from 'lucide-react';
import { useLearningStore, Vocabulary } from '../store/learningStore';
import { vocabularyData, scenes, getSceneVocabulary } from '../data/vocabulary';

export default function PracticePage() {
  const { sceneId } = useParams<{ sceneId: string }>();
  const navigate = useNavigate();
  const [mode, setMode] = useState<'shuffle' | 'sequential'>('sequential');
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);

  const { 
    addLearned, 
    addMastered, 
    removeMastered,
    isLearned, 
    isMastered,
    customVocabulary,
    darkMode
  } = useLearningStore();

  const scene = scenes.find(s => s.id === sceneId);
  
  const allVocabulary: Vocabulary[] = sceneId 
    ? [...getSceneVocabulary(sceneId), ...customVocabulary.filter(v => v.scene === sceneId)]
    : [];

  const vocabulary = allVocabulary.length > 0 ? allVocabulary : [];
  const currentVocab = vocabulary[currentIndex];

  const handleShuffle = useCallback(() => {
    const shuffled = [...vocabulary].sort(() => Math.random() - 0.5);
    return shuffled;
  }, [vocabulary]);

  const [shuffledVocab, setShuffledVocab] = useState<Vocabulary[]>([]);

  useEffect(() => {
    if (mode === 'shuffle') {
      setShuffledVocab(handleShuffle());
    }
  }, [mode, handleShuffle]);

  const displayVocab = mode === 'shuffle' ? shuffledVocab[currentIndex] : currentVocab;

  const handleNext = () => {
    if (currentIndex < vocabulary.length - 1) {
      setCurrentIndex(prev => prev + 1);
      setIsFlipped(false);
      setIsAnimating(true);
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
      setIsFlipped(false);
      setIsAnimating(true);
      setTimeout(() => setIsAnimating(false), 300);
    }
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
    if (sceneId && displayVocab && !isLearned(sceneId, displayVocab.id)) {
      addLearned(sceneId, displayVocab.id);
    }
  };

  const handleMarkMastered = () => {
    if (sceneId && displayVocab) {
      if (isMastered(sceneId, displayVocab.id)) {
        removeMastered(sceneId, displayVocab.id);
      } else {
        addMastered(sceneId, displayVocab.id);
      }
    }
  };

  const handleSpeak = () => {
    if (displayVocab && 'speechSynthesis' in window) {
      const utterance = new SpeechSynthesisUtterance(displayVocab.english);
      utterance.lang = 'en-US';
      utterance.rate = 0.9;
      window.speechSynthesis.speak(utterance);
    }
  };

  const handleRestart = () => {
    setCurrentIndex(0);
    setIsFlipped(false);
    if (mode === 'shuffle') {
      setShuffledVocab(handleShuffle());
    }
  };

  if (!sceneId || !scene) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center">
          <h2 className={`text-2xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} mb-4`}>场景未找到</h2>
          <button
            onClick={() => navigate('/')}
            className="px-6 py-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-colors"
          >
            返回首页
          </button>
        </div>
      </div>
    );
  }

  if (vocabulary.length === 0) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center max-w-md">
          <BookOpen className={`w-16 h-16 mx-auto ${darkMode ? 'text-slate-600' : 'text-gray-300'} mb-4`} />
          <h2 className={`text-2xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} mb-2`}>暂无词汇</h2>
          <p className={`${darkMode ? 'text-slate-400' : 'text-gray-500'} mb-6`}>该场景下还没有词汇，请先添加一些词汇吧</p>
          <button
            onClick={() => navigate(`/scene/${sceneId}`)}
            className="px-6 py-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-colors"
          >
            返回场景页面
          </button>
        </div>
      </div>
    );
  }

  const masteredCount = sceneId 
    ? vocabulary.filter(v => isMastered(sceneId, v.id)).length 
    : 0;

  return (
    <div className={`min-h-screen ${darkMode ? 'bg-slate-900' : 'bg-gradient-to-br from-emerald-50 via-teal-50 to-cyan-50'} p-6`}>
      <div className="max-w-2xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <button
            onClick={() => navigate(`/scene/${sceneId}`)}
            className={`flex items-center gap-2 ${darkMode ? 'text-slate-300 hover:text-emerald-400' : 'text-gray-600 hover:text-emerald-600'} transition-colors`}
          >
            <ArrowLeft className="w-5 h-5" />
            <span>返回</span>
          </button>

          <div className="flex gap-2">
            <button
              onClick={() => setMode('sequential')}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all ${
                mode === 'sequential'
                  ? 'bg-emerald-600 text-white shadow-lg'
                  : darkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700 border border-slate-700' : 'bg-white text-gray-600 hover:bg-gray-50'
              }`}
            >
              <List className="w-4 h-4" />
              顺序
            </button>
            <button
              onClick={() => setMode('shuffle')}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all ${
                mode === 'shuffle'
                  ? 'bg-emerald-600 text-white shadow-lg'
                  : darkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700 border border-slate-700' : 'bg-white text-gray-600 hover:bg-gray-50'
              }`}
            >
              <Shuffle className="w-4 h-4" />
              随机
            </button>
          </div>
        </div>

        <div className="text-center mb-6">
          <h1 className={`text-2xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>{scene.nameCn} - 词汇练习</h1>
          <p className={`${darkMode ? 'text-slate-400' : 'text-gray-500'} mt-2`}>
            {currentIndex + 1} / {vocabulary.length} · 已掌握 {masteredCount} 个
          </p>
        </div>

        <div className="mb-4">
          <div className={`h-2 ${darkMode ? 'bg-slate-700' : 'bg-gray-200'} rounded-full overflow-hidden`}>
            <div 
              className="h-full bg-gradient-to-r from-emerald-500 to-teal-500 transition-all duration-300"
              style={{ width: `${((currentIndex + 1) / vocabulary.length) * 100}%` }}
            />
          </div>
        </div>

        <div 
          className="relative h-80 mb-8 cursor-pointer perspective-1000"
          onClick={handleFlip}
        >
          <div 
            className={`absolute inset-0 transition-all duration-500 transform-style-3d ${
              isFlipped ? 'rotate-y-180' : ''
            } ${isAnimating ? 'scale-95' : 'scale-100'}`}
          >
            <div className="absolute inset-0 backface-hidden">
              <div className={`h-full ${darkMode ? 'bg-slate-800 border border-slate-700' : 'bg-white'} rounded-2xl shadow-xl p-8 flex flex-col items-center justify-center`}>
                <p className={`text-sm ${darkMode ? 'text-emerald-400' : 'text-emerald-600'} mb-4 font-medium`}>点击卡片查看答案</p>
                <h2 className={`text-4xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} text-center mb-4`}>
                  {displayVocab?.english}
                </h2>
                <p className={`${darkMode ? 'text-slate-400' : 'text-gray-400'} text-lg`}>{displayVocab?.phonetic}</p>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleSpeak();
                  }}
                  className={`mt-6 p-3 ${darkMode ? 'bg-slate-700 text-emerald-400 hover:bg-slate-600' : 'bg-emerald-100 text-emerald-600 hover:bg-emerald-200'} rounded-full transition-colors`}
                >
                  <Volume2 className="w-6 h-6" />
                </button>
              </div>
            </div>

            <div className="absolute inset-0 backface-hidden rotate-y-180">
              <div className={`h-full ${darkMode ? 'bg-slate-700 border border-slate-600' : 'bg-gradient-to-br from-emerald-500 to-teal-600'} rounded-2xl shadow-xl p-8 flex flex-col items-center justify-center ${darkMode ? 'text-slate-100' : 'text-white'}`}>
                <p className={`text-sm ${darkMode ? 'text-slate-400' : 'text-emerald-100'} mb-4 font-medium`}>点击卡片返回</p>
                <h2 className={`text-3xl font-bold text-center mb-4 ${darkMode ? 'text-slate-100' : 'text-white'}`}>
                  {displayVocab?.chinese}
                </h2>
                <p className={`${darkMode ? 'text-slate-400' : 'text-emerald-100'} text-lg`}>
                  分类: {displayVocab?.category}
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="flex items-center justify-center gap-4 mb-6">
          <button
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className={`p-3 ${darkMode ? 'bg-slate-800 border border-slate-700' : 'bg-white'} rounded-full shadow-md hover:shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed`}
          >
            <ArrowLeft className={`w-6 h-6 ${darkMode ? 'text-slate-300' : 'text-gray-600'}`} />
          </button>

          <button
            onClick={handleMarkMastered}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl transition-all ${
              sceneId && displayVocab && isMastered(sceneId, displayVocab.id)
                ? 'bg-amber-500 text-white shadow-lg'
                : darkMode ? 'bg-slate-800 border border-slate-700 text-amber-400 hover:bg-slate-700' : 'bg-white text-amber-600 hover:bg-amber-50'
            }`}
          >
            <Check className="w-5 h-5" />
            {sceneId && displayVocab && isMastered(sceneId, displayVocab.id) ? '已掌握' : '标记掌握'}
          </button>

          <button
            onClick={handleNext}
            disabled={currentIndex === vocabulary.length - 1}
            className={`p-3 ${darkMode ? 'bg-slate-800 border border-slate-700' : 'bg-white'} rounded-full shadow-md hover:shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed`}
          >
            <ArrowLeft className={`w-6 h-6 ${darkMode ? 'text-slate-300' : 'text-gray-600'} rotate-180`} />
          </button>
        </div>

        <div className="flex justify-center">
          <button
            onClick={handleRestart}
            className={`flex items-center gap-2 px-6 py-3 rounded-xl transition-colors ${
              darkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700 border border-slate-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
          >
            <RotateCcw className="w-5 h-5" />
            重新开始
          </button>
        </div>
      </div>
    </div>
  );
}
