import { useState } from 'react';
import { Volume2, Check, X, BookOpen, Puzzle, Pencil, ChevronDown, ChevronUp } from 'lucide-react';
import { Vocabulary } from '../../store/learningStore';
import { useLearningStore } from '../../store/learningStore';
import { useSpeech } from '../../hooks/useSpeech';
import { findWordParts } from '../../data/wordParts';
import { getExamples } from '../../data/examples';
import EditVocabularyModal from '../Common/EditVocabularyModal';

interface WordCardProps {
  vocabulary: Vocabulary;
  sceneId: string;
}

export default function WordCard({ vocabulary, sceneId }: WordCardProps) {
  const [isFlipped, setIsFlipped] = useState(false);
  const [showWordParts, setShowWordParts] = useState(false);
  const [showExamples, setShowExamples] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const { speak } = useSpeech();
  const { isMastered, addMastered, removeMastered, darkMode, updateCustomVocabulary, customVocabulary } = useLearningStore();
  
  const mastered = isMastered(sceneId, vocabulary.id);
  const wordParts = findWordParts(vocabulary.english);
  const examples = getExamples(vocabulary.english);
  const isCustom = customVocabulary.some(v => v.id === vocabulary.id) || vocabulary.id.startsWith('custom-');

  const handleSpeak = (e: React.MouseEvent) => {
    e.stopPropagation();
    speak(vocabulary.english);
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const handleToggleMastered = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (mastered) {
      removeMastered(sceneId, vocabulary.id);
    } else {
      addMastered(sceneId, vocabulary.id);
    }
  };

  const handleUpdateVocabulary = (updatedVocab: Partial<Omit<Vocabulary, 'id'>>) => {
    updateCustomVocabulary(vocabulary.id, updatedVocab);
    setShowEditModal(false);
  };

  const hasWordParts = wordParts.prefixes.length > 0 || wordParts.roots.length > 0 || wordParts.suffixes.length > 0;
  const hasExamples = examples.length > 0;

  return (
    <div className="perspective-1000">
      <div 
        className="cursor-pointer"
        onClick={handleFlip}
      >
        <div 
          className={`relative w-full h-48 transition-transform duration-500 transform-style-3d ${
            isFlipped ? 'rotate-y-180' : ''
          }`}
          style={{
            transformStyle: 'preserve-3d',
            transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)',
          }}
        >
          <div 
            className={`absolute inset-0 ${darkMode ? 'bg-slate-800 border border-slate-700' : 'bg-white'} rounded-2xl shadow-lg p-6 flex flex-col backface-hidden`}
            style={{ backfaceVisibility: 'hidden' }}
          >
            <div className="flex items-start justify-between mb-4">
              <span className={`px-3 py-1 ${darkMode ? 'bg-emerald-900/30 text-emerald-400' : 'bg-primary-50 text-primary-500'} text-xs font-medium rounded-full`}>
                {vocabulary.category}
              </span>
              {mastered && (
                <span className={`px-2 py-1 ${darkMode ? 'bg-amber-900/30 text-amber-400' : 'bg-success/10 text-success'} text-xs font-medium rounded-full flex items-center gap-1`}>
                  <Check className="w-3 h-3" /> 已掌握
                </span>
              )}
            </div>
            
            <div className="flex-1 flex flex-col items-center justify-center">
              <h3 className={`font-display text-2xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'} mb-2 text-center`}>
                {vocabulary.english}
              </h3>
              <p className={`${darkMode ? 'text-slate-500' : 'text-gray-400'} text-sm`}>{vocabulary.phonetic}</p>
            </div>
            
            <div className="flex items-center justify-center gap-4 mt-4">
              <button
                onClick={handleSpeak}
                className={`p-3 ${darkMode ? 'bg-emerald-900/30 hover:bg-emerald-900/50 text-emerald-400' : 'bg-primary-50 hover:bg-primary-100 text-primary-500'} rounded-xl transition-colors`}
                title="点击发音"
              >
                <Volume2 className="w-5 h-5" />
              </button>
              <button
                onClick={handleToggleMastered}
                className={`p-3 rounded-xl transition-colors ${
                  mastered 
                    ? `${darkMode ? 'bg-amber-900/30 hover:bg-amber-900/50' : 'bg-success/10 hover:bg-success/20'}` 
                    : `${darkMode ? 'bg-slate-700 hover:bg-slate-600' : 'bg-gray-100 hover:bg-gray-200'}`
                }`}
                title={mastered ? '取消掌握' : '标记为已掌握'}
              >
                {mastered ? (
                  <X className={`w-5 h-5 ${darkMode ? 'text-amber-400' : 'text-success'}`} />
                ) : (
                  <Check className={`w-5 h-5 ${darkMode ? 'text-slate-400' : 'text-gray-400'}`} />
                )}
              </button>
              {isCustom && (
                <button
                  onClick={(e) => { e.stopPropagation(); setShowEditModal(true); }}
                  className={`p-3 ${darkMode ? 'bg-blue-900/30 hover:bg-blue-900/50 text-blue-400' : 'bg-blue-50 hover:bg-blue-100 text-blue-500'} rounded-xl transition-colors`}
                  title="修改单词"
                >
                  <Pencil className="w-5 h-5" />
                </button>
              )}
            </div>
          </div>

          <div 
            className={`absolute inset-0 ${darkMode ? 'bg-slate-700 border border-slate-600' : 'bg-gradient-to-br from-primary-500 to-primary-600'} rounded-2xl shadow-lg p-6 flex flex-col backface-hidden`}
            style={{ 
              backfaceVisibility: 'hidden',
              transform: 'rotateY(180deg)'
            }}
          >
            <h3 className={`font-serif text-2xl font-bold ${darkMode ? 'text-slate-100' : 'text-white'} mb-2 text-center`}>
              {vocabulary.chinese}
            </h3>
            <p className={`${darkMode ? 'text-slate-400' : 'text-white/70'} text-sm text-center mb-4`}>
              {vocabulary.english} / {vocabulary.phonetic}
            </p>
            <button
              onClick={handleSpeak}
              className={`px-6 py-2 ${darkMode ? 'bg-slate-600 hover:bg-slate-500 text-slate-100' : 'bg-white/20 hover:bg-white/30 text-white'} rounded-xl font-medium transition-colors flex items-center gap-2 mx-auto`}
            >
              <Volume2 className="w-4 h-4" />
              发音
            </button>
          </div>
        </div>
      </div>

      <div className="mt-3 space-y-2">
        {hasWordParts && (
          <button
            onClick={() => setShowWordParts(!showWordParts)}
            className={`w-full flex items-center justify-center gap-2 px-4 py-2 rounded-xl transition-colors ${
              darkMode ? 'bg-slate-800 hover:bg-slate-700 text-slate-300' : 'bg-gray-50 hover:bg-gray-100 text-gray-600'
            }`}
          >
            {showWordParts ? (
              <>
                <ChevronUp className="w-4 h-4" />
                收起词根词缀
              </>
            ) : (
              <>
                <Puzzle className="w-4 h-4" />
                查看词根词缀
              </>
            )}
          </button>
        )}

        {hasExamples && (
          <button
            onClick={() => setShowExamples(!showExamples)}
            className={`w-full flex items-center justify-center gap-2 px-4 py-2 rounded-xl transition-colors ${
              darkMode ? 'bg-slate-800 hover:bg-slate-700 text-slate-300' : 'bg-gray-50 hover:bg-gray-100 text-gray-600'
            }`}
          >
            {showExamples ? (
              <>
                <ChevronUp className="w-4 h-4" />
                收起例句
              </>
            ) : (
              <>
                <BookOpen className="w-4 h-4" />
                查看例句 ({examples.length})
              </>
            )}
          </button>
        )}

        {showWordParts && hasWordParts && (
          <div className={`mt-2 p-4 rounded-xl ${darkMode ? 'bg-slate-800' : 'bg-gray-50'}`}>
            <h4 className={`text-sm font-medium mb-2 ${darkMode ? 'text-emerald-400' : 'text-primary-500'}`}>词根词缀</h4>
            <div className="space-y-2">
              {wordParts.prefixes.map((prefix, index) => (
                <div key={`prefix-${index}`} className={`flex items-center gap-2 text-sm ${darkMode ? 'text-slate-300' : 'text-gray-600'}`}>
                  <span className={`px-2 py-0.5 rounded ${darkMode ? 'bg-blue-900/30 text-blue-400' : 'bg-blue-50 text-blue-500'}`}>{prefix.part}</span>
                  <span>{prefix.meaning}</span>
                </div>
              ))}
              {wordParts.roots.map((root, index) => (
                <div key={`root-${index}`} className={`flex items-center gap-2 text-sm ${darkMode ? 'text-slate-300' : 'text-gray-600'}`}>
                  <span className={`px-2 py-0.5 rounded ${darkMode ? 'bg-purple-900/30 text-purple-400' : 'bg-purple-50 text-purple-500'}`}>{root.part}</span>
                  <span>{root.meaning}</span>
                </div>
              ))}
              {wordParts.suffixes.map((suffix, index) => (
                <div key={`suffix-${index}`} className={`flex items-center gap-2 text-sm ${darkMode ? 'text-slate-300' : 'text-gray-600'}`}>
                  <span className={`px-2 py-0.5 rounded ${darkMode ? 'bg-green-900/30 text-green-400' : 'bg-green-50 text-green-500'}`}>{suffix.part}</span>
                  <span>{suffix.meaning}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {showExamples && hasExamples && (
          <div className={`mt-2 p-4 rounded-xl ${darkMode ? 'bg-slate-800' : 'bg-gray-50'}`}>
            <h4 className={`text-sm font-medium mb-2 ${darkMode ? 'text-amber-400' : 'text-orange-500'}`}>例句</h4>
            <div className="space-y-3">
              {examples.map((example, index) => (
                <div key={index} className={`p-3 rounded-lg ${darkMode ? 'bg-slate-700' : 'bg-white'}`}>
                  <p className={`text-sm ${darkMode ? 'text-slate-200' : 'text-gray-800'}`}>{example.sentence}</p>
                  <p className={`text-xs mt-1 ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>{example.translation}</p>
                  {example.source && (
                    <span className={`text-xs mt-1 block ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>来源: {example.source}</span>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {showEditModal && (
        <EditVocabularyModal
          vocabulary={vocabulary}
          onClose={() => setShowEditModal(false)}
          onUpdate={handleUpdateVocabulary}
        />
      )}
    </div>
  );
}