import { useState, useEffect } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { Search as SearchIcon, ArrowLeft, Filter, Headphones, Mic, BookOpen, PenTool } from 'lucide-react';
import { searchVocabulary, scenes } from '../data/vocabulary';
import { useLearningStore, Vocabulary } from '../store/learningStore';
import WordCard from '../components/Vocabulary/WordCard';

type ModuleType = 'all' | 'listening' | 'speaking' | 'reading' | 'writing';

export default function SearchPage() {
  const [searchParams] = useSearchParams();
  const initialQuery = searchParams.get('q') || '';
  
  const [query, setQuery] = useState(initialQuery);
  const [results, setResults] = useState<Vocabulary[]>([]);
  const [selectedModule, setSelectedModule] = useState<ModuleType>('all');
  const [isSearching, setIsSearching] = useState(false);
  const darkMode = useLearningStore((state) => state.darkMode);

  useEffect(() => {
    if (initialQuery) {
      setQuery(initialQuery);
      performSearch(initialQuery);
    }
  }, [initialQuery]);

  const performSearch = (searchQuery: string) => {
    setIsSearching(true);
    setTimeout(() => {
      let searchResults = searchVocabulary(searchQuery);
      
      if (selectedModule !== 'all') {
        const moduleScenes = getModuleScenes(selectedModule);
        searchResults = searchResults.filter(v => moduleScenes.includes(v.scene));
      }
      
      setResults(searchResults);
      setIsSearching(false);
    }, 200);
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      performSearch(query);
    }
  };

  const handleQueryChange = (newQuery: string) => {
    setQuery(newQuery);
    if (newQuery.trim()) {
      performSearch(newQuery);
    } else {
      setResults([]);
    }
  };

  const handleModuleChange = (module: ModuleType) => {
    setSelectedModule(module);
    if (query.trim()) {
      performSearch(query);
    }
  };

  const getModuleScenes = (module: ModuleType): string[] => {
    switch (module) {
      case 'listening':
        return scenes.map(s => s.id);
      case 'speaking':
        return [];
      case 'reading':
        return [];
      case 'writing':
        return [];
      default:
        return scenes.map(s => s.id);
    }
  };

  const getModuleName = (module: ModuleType): string => {
    switch (module) {
      case 'listening': return '听力';
      case 'speaking': return '口语';
      case 'reading': return '阅读';
      case 'writing': return '写作';
      default: return '全部';
    }
  };

  const getModuleIcon = (module: ModuleType) => {
    switch (module) {
      case 'listening': return Headphones;
      case 'speaking': return Mic;
      case 'reading': return BookOpen;
      case 'writing': return PenTool;
      default: return null;
    }
  };

  const groupedResults = results.reduce((acc, vocab) => {
    if (!acc[vocab.scene]) {
      acc[vocab.scene] = [];
    }
    acc[vocab.scene].push(vocab);
    return acc;
  }, {} as Record<string, Vocabulary[]>);

  return (
    <div className={`min-h-screen ${darkMode ? 'bg-slate-900' : 'bg-gray-50'}`}>
      <div className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-200'} border-b sticky top-0 z-40`}>
        <div className="px-6 py-4 max-w-4xl mx-auto">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-4">
              <Link
                to="/"
                className={`p-2 ${darkMode ? 'hover:bg-slate-700' : 'hover:bg-gray-100'} rounded-xl transition-colors`}
              >
                <ArrowLeft className={`w-5 h-5 ${darkMode ? 'text-slate-400' : 'text-gray-600'}`} />
              </Link>
              <h1 className={`font-serif text-xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>搜索词汇</h1>
            </div>
          </div>
          
          <form onSubmit={handleSearch} className="relative">
            <SearchIcon className={`absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 ${darkMode ? 'text-slate-500' : 'text-gray-400'}`} />
            <input
              type="text"
              value={query}
              onChange={(e) => handleQueryChange(e.target.value)}
              placeholder="输入英文单词或中文释义..."
              className={`w-full pl-12 pr-12 py-4 ${darkMode ? 'bg-slate-700 border-slate-600 text-slate-100 placeholder-slate-400' : 'bg-gray-50 border-gray-200 text-gray-800'} border rounded-2xl focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent transition-all`}
              autoFocus
            />
            {query && (
              <button
                type="button"
                onClick={() => handleQueryChange('')}
                className={`absolute right-4 top-1/2 -translate-y-1/2 p-1 ${darkMode ? 'hover:bg-slate-600' : 'hover:bg-gray-200'} rounded-full transition-colors`}
              >
                <span className={`${darkMode ? 'text-slate-400' : 'text-gray-400'} text-lg`}>&times;</span>
              </button>
            )}
          </form>
          
          <div className="flex gap-2 mt-4 overflow-x-auto pb-2 scrollbar-hide">
            {(['all', 'listening', 'speaking', 'reading', 'writing'] as ModuleType[]).map(module => {
              const Icon = getModuleIcon(module);
              return (
                <button
                  key={module}
                  onClick={() => handleModuleChange(module)}
                  className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors flex items-center gap-2 ${
                    selectedModule === module
                      ? 'bg-emerald-500 text-white'
                      : darkMode
                        ? 'bg-slate-700 text-slate-300 hover:bg-slate-600'
                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}
                >
                  {Icon && <Icon className="w-4 h-4" />}
                  {getModuleName(module)}
                </button>
              );
            })}
          </div>
        </div>
      </div>

      <div className="px-6 py-8 max-w-4xl mx-auto">
        {isSearching ? (
          <div className="flex items-center justify-center py-16">
            <div className="w-8 h-8 border-4 border-primary-500 border-t-transparent rounded-full animate-spin" />
          </div>
        ) : results.length > 0 ? (
          <>
            <div className="mb-6 flex items-center justify-between">
              <p className={darkMode ? 'text-slate-400' : 'text-gray-500'}>
                找到 <span className="font-medium text-primary-500">{results.length}</span> 个结果
                <span className={`text-sm ml-2 ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>({getModuleName(selectedModule)})</span>
              </p>
            </div>
            
            <div className="space-y-8">
              {Object.entries(groupedResults).map(([sceneId, vocabs]) => {
                const scene = scenes.find(s => s.id === sceneId);
                return (
                  <div key={sceneId}>
                    <div className="flex items-center gap-3 mb-4">
                      <h2 className={`font-serif text-lg font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>
                        {scene?.nameCn || sceneId}
                      </h2>
                      <span className={`text-sm ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>
                        {vocabs.length} 个词汇
                      </span>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {vocabs.map(vocab => (
                        <WordCard 
                          key={vocab.id} 
                          vocabulary={vocab} 
                          sceneId={vocab.scene} 
                        />
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </>
        ) : query.trim() ? (
          <div className="text-center py-16">
            <div className={`w-16 h-16 mx-auto mb-4 rounded-full ${darkMode ? 'bg-slate-800' : 'bg-gray-100'} flex items-center justify-center`}>
              <SearchIcon className={`w-8 h-8 ${darkMode ? 'text-slate-500' : 'text-gray-400'}`} />
            </div>
            <p className={darkMode ? 'text-slate-400' : 'text-gray-500'}>未找到匹配的词汇</p>
            <p className={`text-sm mt-1 ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>请尝试其他关键词</p>
          </div>
        ) : (
          <div className="text-center py-16">
            <div className={`w-16 h-16 mx-auto mb-4 rounded-full ${darkMode ? 'bg-slate-800' : 'bg-primary-50'} flex items-center justify-center`}>
              <Filter className={`w-8 h-8 ${darkMode ? 'text-slate-500' : 'text-primary-400'}`} />
            </div>
            <p className={darkMode ? 'text-slate-400' : 'text-gray-500'}>输入关键词搜索词汇</p>
            <p className={`text-sm mt-1 ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>支持英文单词或中文释义</p>
          </div>
        )}
      </div>
    </div>
  );
}
