import { useState, useEffect } from 'react';
import { X, Plus, Trash2, Edit3 } from 'lucide-react';
import { useLearningStore } from '../../store/learningStore';
import { scenes } from '../../data/vocabulary';

interface AddVocabularyModalProps {
  isOpen: boolean;
  onClose: () => void;
  defaultScene?: string;
}

export default function AddVocabularyModal({ isOpen, onClose, defaultScene }: AddVocabularyModalProps) {
  const { 
    addCustomVocabulary, 
    addCustomCategory,
    deleteCustomCategory,
    customCategories,
    getSceneCategories,
    darkMode,
    addReviewRecord
  } = useLearningStore();

  const [formData, setFormData] = useState({
    english: '',
    chinese: '',
    phonetic: '',
    scene: defaultScene || 'accommodation',
    category: '',
  });

  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');
  const [error, setError] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editCategoryName, setEditCategoryName] = useState('');

  useEffect(() => {
    if (defaultScene) {
      setFormData(prev => ({ ...prev, scene: defaultScene }));
    }
  }, [defaultScene]);

  const currentCategories = getSceneCategories(formData.scene);
  const scene = scenes.find(s => s.id === formData.scene);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.english.trim() || !formData.chinese.trim()) {
      setError('请填写英文和中文释义');
      return;
    }
    
    const categoryToUse = formData.category.trim() || currentCategories[0] || '考点';

    addCustomVocabulary({
      english: formData.english.trim(),
      chinese: formData.chinese.trim(),
      phonetic: formData.phonetic.trim() || `/${formData.english.trim().split(' ')[0]}/`,
      scene: formData.scene,
      category: categoryToUse,
    });

    if (!currentCategories.includes(formData.category)) {
      addCustomCategory(formData.scene, formData.category);
    }

    setFormData({
      english: '',
      chinese: '',
      phonetic: '',
      scene: formData.scene,
      category: '',
    });
    setError('');
    onClose();
  };

  const handleAddCategory = () => {
    if (!newCategoryName.trim()) return;
    addCustomCategory(formData.scene, newCategoryName.trim());
    setFormData(prev => ({ ...prev, category: newCategoryName.trim() }));
    setNewCategoryName('');
    setIsAddingCategory(false);
  };

  const handleDeleteCategory = (categoryName: string) => {
    deleteCustomCategory(formData.scene, categoryName);
  };

  const handleStartEdit = (categoryName: string) => {
    setEditingId(categoryName);
    setEditCategoryName(categoryName);
  };

  const handleSaveEdit = (oldName: string) => {
    if (!editCategoryName.trim()) return;
    deleteCustomCategory(formData.scene, oldName);
    addCustomCategory(formData.scene, editCategoryName.trim());
    if (formData.category === oldName) {
      setFormData(prev => ({ ...prev, category: editCategoryName.trim() }));
    }
    setEditingId(null);
    setEditCategoryName('');
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden max-h-[90vh] overflow-y-auto`}>
        <div className={`bg-gradient-to-r from-emerald-600 to-teal-600 text-white p-6 sticky top-0 z-10`}>
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold">添加自定义单词</h2>
              <p className="text-emerald-100 mt-1 text-sm">
                支持自定义分类，词汇将永久保存
              </p>
            </div>
            <button
              onClick={onClose}
              className="p-2 hover:bg-white/20 rounded-full transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          {error && (
            <div className={`${darkMode ? 'bg-red-900/30 border-red-700 text-red-400' : 'bg-red-50 border-red-200 text-red-700'} border px-4 py-3 rounded-xl text-sm animate-shake`}>
              {error}
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2">
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                英文单词/短语 <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={formData.english}
                onChange={(e) => setFormData({ ...formData, english: e.target.value })}
                placeholder="例如: accommodation"
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 placeholder-slate-400' : 'border-gray-200 bg-gray-50'
                }`}
              />
            </div>

            <div className="col-span-2">
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                中文释义 <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={formData.chinese}
                onChange={(e) => setFormData({ ...formData, chinese: e.target.value })}
                placeholder="例如: 住宿"
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 placeholder-slate-400' : 'border-gray-200 bg-gray-50'
                }`}
              />
            </div>

            <div className="col-span-2">
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                音标（可选）
              </label>
              <input
                type="text"
                value={formData.phonetic}
                onChange={(e) => setFormData({ ...formData, phonetic: e.target.value })}
                placeholder="例如: /əˌkɒməˈdeɪʃn/"
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 placeholder-slate-400' : 'border-gray-200 bg-gray-50'
                }`}
              />
            </div>

            <div className="col-span-2">
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                场景分类
              </label>
              <select
                value={formData.scene}
                onChange={(e) => setFormData(prev => ({ ...prev, scene: e.target.value, category: '' }))}
                className={`w-full px-4 py-3 border rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${
                  darkMode ? 'border-slate-600 bg-slate-700 text-slate-100' : 'border-gray-200 bg-gray-50'
                }`}
              >
                {scenes.map((s) => (
                  <option key={s.id} value={s.id}>
                    {s.nameCn} ({s.name})
                  </option>
                ))}
              </select>
            </div>

            <div className="col-span-2">
              <label className={`block text-sm font-medium ${darkMode ? 'text-slate-300' : 'text-gray-700'} mb-2`}>
                词汇分类 <span className="text-red-500">*</span>
              </label>
              
              <div className="flex gap-2 mb-2">
                <select
                  value={formData.category}
                  onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                  className={`flex-1 px-4 py-3 border rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all ${
                    darkMode ? 'border-slate-600 bg-slate-700 text-slate-100' : 'border-gray-200 bg-gray-50'
                  }`}
                >
                  <option value="">选择分类...</option>
                  {currentCategories.map((cat) => (
                    <option key={cat} value={cat}>
                      {cat}
                    </option>
                  ))}
                </select>
                <button
                  type="button"
                  onClick={() => setIsAddingCategory(true)}
                  className={`px-4 py-3 ${darkMode ? 'bg-emerald-900/30 text-emerald-400 hover:bg-emerald-900/50' : 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200'} rounded-xl transition-colors flex items-center gap-2`}
                >
                  <Plus className="w-4 h-4" />
                  新建
                </button>
              </div>

              {isAddingCategory && (
                <div className="flex gap-2 mb-3">
                  <input
                    type="text"
                    value={newCategoryName}
                    onChange={(e) => setNewCategoryName(e.target.value)}
                    placeholder="输入新分类名称..."
                    className={`flex-1 px-4 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500 focus:border-transparent ${
                      darkMode ? 'border-slate-600 bg-slate-700 text-slate-100 placeholder-slate-400' : 'border-emerald-300 bg-white'
                    }`}
                    autoFocus
                    onKeyDown={(e) => e.key === 'Enter' && handleAddCategory()}
                  />
                  <button
                    type="button"
                    onClick={handleAddCategory}
                    className="px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors"
                  >
                    添加
                  </button>
                  <button
                    type="button"
                    onClick={() => {
                      setIsAddingCategory(false);
                      setNewCategoryName('');
                    }}
                    className={`px-4 py-2 ${darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-200 text-gray-600 hover:bg-gray-300'} rounded-lg transition-colors`}
                  >
                    取消
                  </button>
                </div>
              )}

              {customCategories.filter(c => c.sceneId === formData.scene).length > 0 && (
                <div className="mt-3">
                  <p className={`text-xs ${darkMode ? 'text-slate-500' : 'text-gray-500'} mb-2`}>已创建的自定义分类（可编辑/删除）：</p>
                  <div className="flex flex-wrap gap-2">
                    {customCategories
                      .filter(c => c.sceneId === formData.scene)
                      .map((cat) => (
                        <div
                          key={cat.name}
                          className={`group flex items-center gap-1 px-3 py-1 ${darkMode ? 'bg-slate-700 border-slate-600' : 'bg-amber-50 border-amber-200'} border rounded-full`}
                        >
                          {editingId === cat.name ? (
                            <>
                              <input
                                type="text"
                                value={editCategoryName}
                                onChange={(e) => setEditCategoryName(e.target.value)}
                                className={`w-20 px-2 py-0.5 text-sm border rounded ${
                                  darkMode ? 'bg-slate-600 border-slate-500 text-slate-100' : ''
                                }`}
                                autoFocus
                                onKeyDown={(e) => e.key === 'Enter' && handleSaveEdit(cat.name)}
                              />
                              <button
                                onClick={() => handleSaveEdit(cat.name)}
                                className="text-emerald-600 hover:text-emerald-800"
                              >
                                ✓
                              </button>
                            </>
                          ) : (
                            <>
                              <span className={`text-sm ${darkMode ? 'text-slate-300' : 'text-amber-800'}`}>{cat.name}</span>
                              <button
                                type="button"
                                onClick={() => handleStartEdit(cat.name)}
                                className={`opacity-0 group-hover:opacity-100 ${darkMode ? 'text-slate-500 hover:text-blue-400' : 'text-gray-400 hover:text-blue-600'} transition-all`}
                              >
                                <Edit3 className="w-3 h-3" />
                              </button>
                              <button
                                type="button"
                                onClick={() => handleDeleteCategory(cat.name)}
                                className={`opacity-0 group-hover:opacity-100 ${darkMode ? 'text-slate-500 hover:text-red-400' : 'text-gray-400 hover:text-red-600'} transition-all`}
                              >
                                <Trash2 className="w-3 h-3" />
                              </button>
                            </>
                          )}
                        </div>
                      ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="pt-4">
            <button
              type="submit"
              className="w-full bg-gradient-to-r from-emerald-600 to-teal-600 text-white py-4 px-6 rounded-xl font-semibold hover:from-emerald-700 hover:to-teal-700 transition-all transform hover:scale-[1.01] active:scale-[0.99] shadow-lg shadow-emerald-500/30 flex items-center justify-center gap-2"
            >
              <Plus className="w-5 h-5" />
              添加到学习列表
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
