import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  ArrowLeft, 
  Volume2, 
  BookOpen,
  Award,
  BookMarked,
  Plus,
  RotateCcw,
  Trash2,
  X
} from 'lucide-react';
import { scenes } from '../data/vocabulary';
import { useLearningStore } from '../store/learningStore';
import { useSpeech } from '../hooks/useSpeech';
import AddVocabularyModal from '../components/Common/AddVocabularyModal';

export default function ListeningPage() {
  const navigate = useNavigate();
  const { speak } = useSpeech();
  const { resetSceneProgress, resetAllProgress, wrongAnswers, darkMode } = useLearningStore();
  const [currentView, setCurrentView] = useState<'scenes' | 'wrong' | 'favorites'>('scenes');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showResetModal, setShowResetModal] = useState(false);
  const [resetTarget, setResetTarget] = useState<string | 'all'>('all');

  const handleResetProgress = () => {
    if (resetTarget === 'all') {
      resetAllProgress();
    } else {
      resetSceneProgress(resetTarget);
    }
    setShowResetModal(false);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${darkMode ? 'bg-slate-900' : 'bg-gray-50'}`}>
      <div className={`border-b sticky top-0 z-40 transition-colors duration-300 ${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-200'}`}>
        <div className="px-6 py-4 max-w-6xl mx-auto">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button
                onClick={() => navigate('/')}
                className={`p-2 rounded-xl transition-colors ${darkMode ? 'hover:bg-slate-700' : 'hover:bg-gray-100'}`}
              >
                <ArrowLeft className={`w-5 h-5 ${darkMode ? 'text-slate-400' : 'text-gray-600'}`} />
              </button>
              <div>
                <h1 className={`font-serif text-xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>听力词汇学习</h1>
              </div>
            </div>
            
            <div className="flex items-center gap-2">
              <button
                onClick={() => setShowAddModal(true)}
                className="btn-primary flex items-center gap-2"
              >
                <Plus className="w-5 h-5" />
                添加单词
              </button>
              
              <button
                onClick={() => setShowResetModal(true)}
                className={`px-4 py-2 rounded-xl font-medium transition-colors flex items-center gap-2 ${
                  darkMode ? 'bg-red-900/30 text-red-400 hover:bg-red-900/50' : 'bg-red-50 text-red-600 hover:bg-red-100'
                }`}
              >
                <RotateCcw className="w-5 h-5" />
                重置进度
              </button>
            </div>
          </div>
          
          <div className={`flex gap-4 mt-4 border-t pt-4 ${darkMode ? 'border-slate-700' : 'border-gray-100'}`}>
            <button
              onClick={() => setCurrentView('scenes')}
              className={`px-4 py-2 rounded-xl font-medium transition-colors ${
                currentView === 'scenes'
                  ? 'bg-emerald-500 text-white'
                  : darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              场景选择
            </button>
            <button
              onClick={() => setCurrentView('wrong')}
              className={`px-4 py-2 rounded-xl font-medium transition-colors ${
                currentView === 'wrong'
                  ? 'bg-red-500 text-white'
                  : darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              错题本
            </button>
            <button
              onClick={() => setCurrentView('favorites')}
              className={`px-4 py-2 rounded-xl font-medium transition-colors ${
                currentView === 'favorites'
                  ? 'bg-purple-500 text-white'
                  : darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              收藏词
            </button>
          </div>
        </div>
      </div>

      <div className="px-6 py-8 max-w-6xl mx-auto">
        {currentView === 'scenes' && (
          <SceneSelection />
        )}
        
        {currentView === 'wrong' && (
          <WrongAnswers wrongAnswers={wrongAnswers} />
        )}
        
        {currentView === 'favorites' && (
          <Favorites />
        )}
      </div>

      <AddVocabularyModal 
        isOpen={showAddModal} 
        onClose={() => setShowAddModal(false)} 
      />

      {showResetModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className={`${darkMode ? 'bg-slate-800' : 'bg-white'} rounded-3xl max-w-md w-full max-h-[90vh] overflow-hidden flex flex-col`}>
            <div className={`flex items-center justify-between p-6 ${darkMode ? 'border-slate-700 border-b' : 'border-gray-100 border-b'}`}>
              <h3 className={`text-xl font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>重置进度</h3>
              <button
                onClick={() => setShowResetModal(false)}
                className={`p-2 ${darkMode ? 'hover:bg-slate-700' : 'hover:bg-gray-100'} rounded-full transition-colors`}
              >
                <X className={`w-5 h-5 ${darkMode ? 'text-slate-400' : 'text-gray-600'}`} />
              </button>
            </div>
            
            <div className="flex-1 overflow-y-auto p-6">
              <div className="space-y-2">
                <button
                  onClick={() => setResetTarget('all')}
                  className={`w-full px-4 py-3 text-left rounded-xl transition-colors flex items-center gap-3 ${
                    resetTarget === 'all'
                      ? `${darkMode ? 'bg-emerald-900/30 text-emerald-400 border-2 border-emerald-500' : 'bg-emerald-50 text-emerald-700 border-2 border-emerald-500'}`
                      : `${darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600 border-2 border-transparent' : 'bg-gray-50 text-gray-700 hover:bg-gray-100 border-2 border-transparent'}`
                  }`}
                >
                  <Trash2 className="w-5 h-5 text-red-600" />
                  <span className="font-medium">重置全部进度</span>
                </button>
                
                {scenes.map(scene => (
                  <button
                    key={scene.id}
                    onClick={() => setResetTarget(scene.id)}
                    className={`w-full px-4 py-3 text-left rounded-xl transition-colors flex items-center gap-3 ${
                      resetTarget === scene.id
                        ? `${darkMode ? 'bg-emerald-900/30 text-emerald-400 border-2 border-emerald-500' : 'bg-emerald-50 text-emerald-700 border-2 border-emerald-500'}`
                        : `${darkMode ? 'bg-slate-700 text-slate-300 hover:bg-slate-600 border-2 border-transparent' : 'bg-gray-50 text-gray-700 hover:bg-gray-100 border-2 border-transparent'}`
                    }`}
                  >
                    <span className="text-lg">{scene.icon}</span>
                    <span className="font-medium">{scene.nameCn}</span>
                  </button>
                ))}
              </div>
            </div>
            
            <div className={`p-6 ${darkMode ? 'border-slate-700 border-t' : 'border-gray-100 border-t'}`}>
              <button
                onClick={handleResetProgress}
                className="w-full px-4 py-3 bg-red-500 text-white rounded-xl font-medium hover:bg-red-600 transition-colors"
              >
                确认重置
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function SceneSelection() {
  const { getLearnedCount, getMasteredCount, darkMode, getAllVocabulary, getVocabularyByScene } = useLearningStore();
  const navigate = useNavigate();
  
  const allVocab = getAllVocabulary();
  const totalLearned = scenes.reduce((sum, scene) => sum + getLearnedCount(scene.id), 0);
  const totalMastered = scenes.reduce((sum, scene) => sum + getMasteredCount(scene.id), 0);
  const totalVocab = allVocab.length;

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      <div 
        className="bg-gradient-to-br from-emerald-500 to-teal-500 rounded-2xl p-4 shadow-sm cursor-pointer hover:shadow-md transition-all hover:scale-[1.02]"
        onClick={() => navigate('/scene/all')}
      >
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center shadow-sm">
              <BookOpen className="w-5 h-5 text-white" />
            </div>
            <div>
              <h3 className="font-bold text-white">全部词汇</h3>
              <p className="text-xs text-emerald-100">所有场景词汇汇总</p>
            </div>
          </div>
        </div>
        
        <div className="flex items-center justify-between text-sm mb-2">
          <span className="text-white/90 font-medium">{totalLearned}/{totalVocab}</span>
          <span className="text-amber-200">{totalMastered} 已掌握</span>
        </div>
        
        <div className="w-full bg-white/20 rounded-full h-2">
          <div 
            className="bg-white h-2 rounded-full transition-all"
            style={{ width: `${totalVocab > 0 ? Math.round((totalLearned / totalVocab) * 100) : 0}%` }}
          />
        </div>
      </div>
      
      {scenes.map((scene) => {
        const vocabularyCount = getVocabularyByScene(scene.id).length;
        const learnedCount = getLearnedCount(scene.id);
        const masteredCount = getMasteredCount(scene.id);
        const progress = vocabularyCount > 0 
          ? Math.round((learnedCount / vocabularyCount) * 100) 
          : 0;

        return (
          <div 
            key={scene.id} 
            className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-gray-100'} rounded-2xl p-4 shadow-sm cursor-pointer hover:shadow-md transition-all hover:border-emerald-200 border-2 border-transparent`}
            onClick={() => navigate(`/scene/${scene.id}`)}
          >
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 bg-gradient-to-br ${scene.gradient} rounded-xl flex items-center justify-center shadow-sm`}>
                  <span className="text-lg">{scene.icon}</span>
                </div>
                <div>
                  <h3 className={`font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>{scene.nameCn}</h3>
                  <p className={`text-xs ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>{scene.description}</p>
                </div>
              </div>
            </div>
            
            <div className="flex items-center justify-between text-sm mb-2">
              <span className={`font-medium ${darkMode ? 'text-emerald-400' : 'text-emerald-600'}`}>{learnedCount}/{vocabularyCount}</span>
              <span className={darkMode ? 'text-amber-400' : 'text-amber-600'}>{masteredCount} 已掌握</span>
            </div>
            
            <div className={`w-full ${darkMode ? 'bg-slate-700' : 'bg-gray-100'} rounded-full h-2`}>
              <div 
                className={`bg-gradient-to-r ${scene.gradient} h-2 rounded-full transition-all`}
                style={{ width: `${progress}%` }}
              />
            </div>
          </div>
        );
      })}
    </div>
  );
}

function WrongAnswers({ wrongAnswers }: { wrongAnswers: any[] }) {
  const { speak } = useSpeech();
  const { darkMode } = useLearningStore();

  if (wrongAnswers.length === 0) {
    return (
      <div className="text-center py-16">
        <div className={`w-16 h-16 mx-auto mb-4 rounded-full ${darkMode ? 'bg-slate-800' : 'bg-emerald-100'} flex items-center justify-center`}>
          <Award className={`w-8 h-8 ${darkMode ? 'text-emerald-400' : 'text-emerald-600'}`} />
        </div>
        <p className={darkMode ? 'text-slate-400' : 'text-gray-500'}>暂无错题</p>
        <p className={`text-sm mt-1 ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>太棒了！你没有需要复习的单词</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      {wrongAnswers.map((vocab) => (
        <div key={vocab.id} className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white'} rounded-2xl p-4 shadow-sm border`}>
          <div className="flex items-center justify-between mb-2">
            <h3 className={`font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>{vocab.english}</h3>
            <button
              onClick={() => speak(vocab.english)}
              className={`p-2 ${darkMode ? 'bg-emerald-900 text-emerald-400 hover:bg-emerald-800' : 'bg-emerald-100 text-emerald-600 hover:bg-emerald-200'} rounded-xl transition-colors`}
            >
              <Volume2 className="w-4 h-4" />
            </button>
          </div>
          <p className={`text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>{vocab.chinese}</p>
          {vocab.phonetic && (
            <p className={`text-xs ${darkMode ? 'text-slate-500' : 'text-gray-400'} mt-1`}>{vocab.phonetic}</p>
          )}
        </div>
      ))}
    </div>
  );
}

function Favorites() {
  const favorites = useLearningStore(state => state.favorites);
  const { speak } = useSpeech();
  const { darkMode } = useLearningStore();

  if (favorites.length === 0) {
    return (
      <div className="text-center py-16">
        <div className={`w-16 h-16 mx-auto mb-4 rounded-full ${darkMode ? 'bg-slate-800' : 'bg-purple-100'} flex items-center justify-center`}>
          <BookMarked className={`w-8 h-8 ${darkMode ? 'text-purple-400' : 'text-purple-600'}`} />
        </div>
        <p className={darkMode ? 'text-slate-400' : 'text-gray-500'}>暂无收藏</p>
        <p className={`text-sm mt-1 ${darkMode ? 'text-slate-500' : 'text-gray-400'}`}>在单词列表中点击收藏按钮添加</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
      {favorites.map((vocab: any) => (
        <div key={vocab.id} className={`${darkMode ? 'bg-slate-800 border-slate-700' : 'bg-white'} rounded-2xl p-4 shadow-sm border`}>
          <div className="flex items-center justify-between mb-2">
            <h3 className={`font-bold ${darkMode ? 'text-slate-100' : 'text-gray-800'}`}>{vocab.english}</h3>
            <button
              onClick={() => speak(vocab.english)}
              className={`p-2 ${darkMode ? 'bg-emerald-900 text-emerald-400 hover:bg-emerald-800' : 'bg-emerald-100 text-emerald-600 hover:bg-emerald-200'} rounded-xl transition-colors`}
            >
              <Volume2 className="w-4 h-4" />
            </button>
          </div>
          <p className={`text-sm ${darkMode ? 'text-slate-400' : 'text-gray-500'}`}>{vocab.chinese}</p>
          {vocab.phonetic && (
            <p className={`text-xs ${darkMode ? 'text-slate-500' : 'text-gray-400'} mt-1`}>{vocab.phonetic}</p>
          )}
        </div>
      ))}
    </div>
  );
}
